window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q20"]=window.__LIBQ["tien-nghich"]["q20"]||{};window.__LIBQ["tien-nghich"]["q20"]["artifacts"]={"updatedAt":"2026-07-16","count":58,"artifacts":[{"id":"ngoc-gian-co-nhai-giao-vuong-lam","name":"Ngọc giản Cô Nhai giao Vương Lâm","cn":"","category":"khac","categoryLabel":"Vật phẩm liên lạc","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Ngọc giản do Cô Nhai Thiên Tôn giao cho Vương Lâm trước chuyến đi Trung Châu.","detail":"Cô Nhai nói đã đưa ngọc giản cho Vương Lâm. Nếu hắn ở Trung Châu gặp nguy cơ không giải quyết được, Oa Oa và Hàm Hàm sẽ lập tức biết để nhờ Song Tử Đại Thiên Tôn trợ giúp.","phanLoaiPhu":"vật phẩm liên lạc, cầu viện","congNang":["Báo cho Oa Oa và Hàm Hàm biết khi Vương Lâm gặp nguy cơ không giải quyết được ở Trung Châu @c1867"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1867","denChuong":"","cachCoDuoc":"Cô Nhai Thiên Tôn giao trước chuyến đi Trung Châu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1867","loai":"xuất hiện","importance":"normal","giaiDoan":"Cầu viện Trung Châu","text":"Cô Nhai Thiên Tôn xác nhận đã giao ngọc giản cho Vương Lâm để báo nguy khi hắn gặp chuyện không giải quyết được ở Trung Châu.","anchor":"ta đã đưa ngọc giản cho hắn, một khi ở Trung Châu gặp phải nguy cơ không giải quyết được"}]},"capNhatToi":"@c1867","nguon":["@c1867"]},{"id":"gia-go-mau-tim-trong-mat-that-ly-phu","name":"Giá gỗ màu tím trong mật thất Lý Phủ","cn":"","aliases":["Giá cung của lão tổ"],"category":"phap-bao","categoryLabel":"Giá cung","phamCap":"không rõ","soHuu":["Lý Phủ","Lão già trong mật thất Lý Phủ"],"trangThai":"đang ở Lý Phủ","blurb":"Giá gỗ màu tím đặt trong mật thất Lý Phủ, hình như thiếu một cây cung. Khi cung của lão tổ xuất hiện gần, giá phát tiếng cung reo và hóa ra mũi tên màu tím để dò khí tức.","detail":"Trong mật thất đá xanh của Lý Phủ, lão già ngồi trước một giá gỗ màu tím không có cung. Khi Vương Lâm mang cây cung của Lý Quảng vào Đông Thành, giá gỗ phát ra tiếng cung reo, khiến lão già nhận định cung của lão tổ đã xuất hiện gần đó và kích hoạt mũi tên màu tím đi dò tìm.","phanLoaiPhu":"giá cung cảm ứng","hinhDang":"giá gỗ màu tím, hình như thiếu một cây cung","chuHienThoi":"Lý Phủ","congNang":["Cảm ứng khi cung của lão tổ xuất hiện trong phạm vi gần @c1868","Hóa ra mũi tên màu tím để dò khí tức cây cung @c1868"],"uyLuc":"Có thể dẫn Lý Phủ phát hiện dấu vết cung của lão tổ khi vật này xuất hiện gần Đông Thành.","dacDiem":"Tiếng cung reo phát ra từ giá gỗ dù trên giá không có cung.","chuSoHuu":[{"ten":"Lý Phủ","tuChuong":"@c1868","denChuong":"","cachCoDuoc":"đặt trong mật thất Lý Phủ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1868","loai":"xuất hiện","importance":"normal","giaiDoan":"Cảm ứng cung lão tổ","text":"Giá gỗ màu tím trong mật thất Lý Phủ phát tiếng cung reo khi cung của lão tổ xuất hiện gần, rồi hóa ra mũi tên màu tím để dò khí tức.","anchor":"tiếng cung reo không ngờ lại truyền từ trong giá gỗ này ra","phamCap":"không rõ"}]},"capNhatToi":"@c1868","nguon":["@c1868"]},{"id":"mui-ten-mau-tim-cua-ly-phu","name":"Mũi tên màu tím của Lý Phủ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Mũi tên linh quang","phamCap":"không rõ","soHuu":["Lý Phủ","Tu sĩ Lý gia huyết ảnh"],"trangThai":"bị phá trong cuộc tập kích Vương Lâm","blurb":"Mũi tên màu tím do giá gỗ trong mật thất Lý Phủ hóa ra để dò khí tức cây cung. Sau đó nó được dùng trong đòn tập kích Vương Lâm nhưng bị một chỉ đánh tan.","detail":"Sau khi giá cung trong mật thất Lý Phủ reo vang, lão già vung tay khiến giá gỗ hóa ra một luồng sáng tím thành hình mũi tên và bay ra ngoài để tìm khí tức cung của lão tổ. Về sau mũi tên xuất hiện trước thân ảnh tập kích Vương Lâm, lao tới hắn và bị một chỉ phá nát.","phanLoaiPhu":"mũi tên dò tìm và công kích","hinhDang":"luồng sáng màu tím hóa thành hình mũi tên","chuHienThoi":"Lý Phủ","congNang":["Dò tìm khí tức cây cung của lão tổ @c1868","Kích phát thành đòn công kích nhằm vào Vương Lâm @c1868"],"uyLuc":"Có thể dẫn đường dò khí tức và được dùng trong đòn công kích, nhưng bị Vương Lâm dùng một chỉ đánh tan.","dacDiem":"Sinh ra từ giá gỗ màu tím trong mật thất Lý Phủ.","chuSoHuu":[{"ten":"Lý Phủ","tuChuong":"@c1868","denChuong":"","cachCoDuoc":"hóa ra từ giá gỗ màu tím","trangThai":"đã dùng"},{"ten":"Tu sĩ Lý gia huyết ảnh","tuChuong":"@c1868","denChuong":"@c1868","cachCoDuoc":"dùng trong lúc tập kích Vương Lâm","trangThai":"bị phá"}],"tabs":{"tienTrinh":[{"chuong":"@c1868","loai":"dùng","importance":"normal","giaiDoan":"Dò cung và tập kích","text":"Mũi tên màu tím được giá gỗ Lý Phủ hóa ra để dò khí tức cung của lão tổ, rồi xuất hiện trong đòn tập kích Vương Lâm và bị một chỉ đánh tan.","anchor":"một luồng sáng màu tím lóe lên, bất ngờ hóa thành hình dáng một mũi tên","phamCap":"không rõ"}]},"capNhatToi":"@c1868","nguon":["@c1868"]},{"id":"cay-cung-bien-ao-cua-tu-si-ly-gia","name":"Cây cung biến ảo của tu sĩ Lý gia","cn":"","aliases":["Cung ảnh của tu sĩ Lý gia"],"category":"phap-bao","categoryLabel":"Cung ảnh","phamCap":"không rõ","soHuu":["Tu sĩ Lý gia huyết ảnh"],"trangThai":"bị phá trong một chỉ của Vương Lâm","blurb":"Cây cung do tu sĩ Lý gia huyết ảnh biến ảo ra trong lúc tập kích Vương Lâm. Mũi tên bắn ra từ cung này bị Vương Lâm dùng một chỉ phá tan cùng mũi tên màu tím.","detail":"Khi bị Vương Lâm ép hiện thân, tu sĩ Lý gia huyết ảnh lập tức bắt quyết biến ảo ra một cây cung, như có bàn tay vô hình kéo dây và bắn thêm một mũi tên về phía Vương Lâm. Đòn này thuộc toàn lực Kim Tôn nhưng vẫn bị Vương Lâm tùy ý hóa giải.","phanLoaiPhu":"cung ảnh công kích","hinhDang":"cây cung biến ảo khi bắt quyết","chuHienThoi":"Tu sĩ Lý gia huyết ảnh","congNang":["Biến ảo thành cung để bắn mũi tên công kích mục tiêu @c1868"],"uyLuc":"Đòn bắn từ cung ảnh là toàn lực Kim Tôn nhưng không chống nổi một chỉ của Vương Lâm.","dacDiem":"Xuất hiện tức thời từ pháp quyết của tu sĩ Lý gia huyết ảnh.","chuSoHuu":[{"ten":"Tu sĩ Lý gia huyết ảnh","tuChuong":"@c1868","denChuong":"@c1868","cachCoDuoc":"biến ảo bằng pháp quyết khi tập kích","trangThai":"bị phá"}],"tabs":{"tienTrinh":[{"chuong":"@c1868","loai":"dùng","importance":"normal","giaiDoan":"Bắn Vương Lâm","text":"Tu sĩ Lý gia huyết ảnh bắt quyết biến ảo ra cung và bắn thêm một mũi tên về phía Vương Lâm, nhưng đòn này bị phá cùng mũi tên màu tím.","anchor":"Người này vừa xuất hiện liền không chút do dự lập tức bắt quyết","phamCap":"không rõ"}]},"capNhatToi":"@c1868","nguon":["@c1868"]},{"id":"mui-ten-mau-den","name":"Mũi tên màu đen","cn":"","aliases":[],"category":"khac","categoryLabel":"Vũ khí","phamCap":"không rõ","soHuu":["Nam tử trung niên truy kích của Lý Phủ"],"trangThai":"bị phá hủy","blurb":"Mũi tên màu đen của kẻ truy kích Lý Phủ, từng cắm vào bụng Hải Long. Nó tỏa lực phá hủy sinh cơ, khiến Hải Long trọng thương và toàn thân tràn ngập hắc khí.","detail":"Mũi tên màu đen làm Hải Long bị thương nặng trong lúc chở Lưu Kim Bưu bỏ chạy. Vương Lâm vuốt đầu Hải Long khiến hắc khí tan đi, rút mũi tên ra rồi bóp nát thành bụi.","phanLoaiPhu":"mũi tên","hinhDang":"mũi tên màu đen","uyLuc":"Làm Hải Long trọng thương và phá hoại sinh cơ.","dacDiem":"Tỏa hắc khí ăn mòn sinh cơ quanh vết thương.","congNang":["Phá hủy sinh cơ và làm mục tiêu tràn ngập hắc khí @c1869"],"chuHienThoi":"Nam tử trung niên truy kích của Lý Phủ","chuSoHuu":[{"ten":"Nam tử trung niên truy kích của Lý Phủ","tuChuong":"@c1869","denChuong":"@c1869","cachCoDuoc":"Dùng trong truy sát Lưu Kim Bưu và Hải Long","trangThai":"mất khi bị Vương Lâm bóp nát"}],"capNhatToi":"@c1869","tabs":{"tienTrinh":[{"chuong":"@c1869","loai":"dùng","importance":"normal","giaiDoan":"Bắn trọng thương Hải Long","text":"Mũi tên màu đen cắm vào bụng Hải Long, tỏa hắc khí phá sinh cơ, rồi bị Vương Lâm rút ra và bóp nát.","anchor":"còn có một mũi tên màu đen đâm vào một nửa","phamCap":"không rõ"}]},"dinhDanh":"goc","nguon":["@c1869"]},{"id":"cung-cua-nam-tu-trung-nien-ly-phu","name":"Cung của nam tử trung niên Lý Phủ","cn":"","aliases":[],"category":"khac","categoryLabel":"Vũ khí","phamCap":"không rõ","soHuu":["Nam tử trung niên truy kích của Lý Phủ"],"trangThai":"không rõ","blurb":"Cây cung do nam tử trung niên Lý Phủ dùng khi truy sát Lưu Kim Bưu và Hải Long. Khi bắn, nó khiến tiên khí xung quanh ngưng tụ vào mũi tên.","detail":"Kẻ truy kích áo đen cầm cây cung này và bắn mũi tên thứ hai trong lúc đuổi theo Lưu Kim Bưu, Hải Long. Mũi tên mang sát khí lao tới nhưng bị Vương Lâm phá nát bằng ánh mắt.","phanLoaiPhu":"cung","hinhDang":"cây cung cầm tay","uyLuc":"Bắn ra mũi tên ngưng tụ tiên khí trong truy sát.","dacDiem":"Gắn với cung thuật của người Lý Phủ.","congNang":["Bắn tên ngưng tụ tiên khí xung quanh @c1869"],"chuHienThoi":"Nam tử trung niên truy kích của Lý Phủ","chuSoHuu":[{"ten":"Nam tử trung niên truy kích của Lý Phủ","tuChuong":"@c1869","denChuong":"","cachCoDuoc":"Mang theo khi truy sát","trangThai":"không rõ"}],"capNhatToi":"@c1869","tabs":{"tienTrinh":[{"chuong":"@c1869","loai":"dùng","importance":"normal","giaiDoan":"Bắn mũi tên thứ hai","text":"Nam tử trung niên Lý Phủ dùng cây cung này bắn mũi tên thứ hai trong lúc truy sát Lưu Kim Bưu và Hải Long.","anchor":"trong tay rõ ràng có một cây cung","phamCap":"không rõ"}]},"dinhDanh":"goc","nguon":["@c1869"]},{"id":"hai-su-tu-da-truoc-ly-phu","name":"Hai sư tử đá trước Lý Phủ","cn":"","aliases":[],"category":"khac","categoryLabel":"Trấn môn","phamCap":"không rõ","soHuu":["Lý Phủ"],"trangThai":"bị phá hủy","blurb":"Hai tượng sư tử đá trấn giữ đại môn Lý Phủ, có khả năng tự mở mắt, gầm vang và hóa hư ảnh sư tử khổng lồ để công kích kẻ xâm nhập. Chúng bị phá hủy khi đối đầu Vương Lâm tại chương 1869.","detail":"Hai sư tử đá đặt trước cổng lớn Lý Phủ, đóng vai trò trấn thủ tự động. Khi Lưu Kim Bưu đi qua, chúng nhắm mắt không phảnứng, cho thấy có cơ chế nhận diện người được phép ra vào. Tuy nhiên khi Vương Lâm bước vào, hai tượng lập tức mở mắt, phát tiếng gầm lan ra hơn nửa Đông Thành và hóa thành hư ảnh sư tử khổng lồ lao tới tấn công. Trước sức mạnh của Vương Lâm, hư ảnh tan biến còn bản thể tượng đá nứt vỡ thành nhiều mảnh.","phanLoaiPhu":"thủ vệ trấn môn","hinhDang":"hai tượng sư tử đá trước đại môn","uyLuc":"Có thể hóa hư ảnh sư tử khổng lồ công kích người xông phủ, tiếng gầm lan ra hơn nửa Đông Thành.","dacDiem":"Tiếng gầm lan ra hơn nửa Đông Thành; cóơ chế nhận diện — nhắm mắt để người quen đi qua, mở mắt tấn công kẻ lạ.","congNang":["Trấn thủ đại môn Lý Phủ, tự động phân biệt người được phép và kẻ xâm nhập @c1869","Hóa hư ảnh sư tử khổng lồ công kích người xông vào phủ @c1869","Phát tiếng gầm cảnh báo lan ra hơn nửa Đông Thành @c1869"],"chuHienThoi":"Lý Phủ","chuSoHuu":[{"ten":"Lý Phủ","tuChuong":"@c1869","denChuong":"@c1869","cachCoDuoc":"Đặt trước đại môn làm thủ vệ","trangThai":"bị Vương Lâm phá hủy"}],"capNhatToi":"@c1869","tabs":{"tienTrinh":[{"chuong":"@c1869","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị phá trước đại môn","text":"Hai sư tử đá trước Lý Phủ mở mắt hóa hư ảnh công kích Vương Lâm, nhưng hư ảnh tan biến và tượng đá nứt vỡ thành nhiều mảnh.","anchor":"Hai con sư tử đá bên cạnh đại môn xuất hiện những khe nứt","phamCap":"không rõ"}]},"dinhDanh":"goc","nguon":["@c1869"]},{"id":"thanh-chi-sac-phong-cua-tien-hoang","name":"Thánh chỉ sắc phong của Tiên Hoàng","cn":"","category":"khac","categoryLabel":"Chiếu chỉ","phamCap":"","soHuu":["Tiên Hoàng"],"trangThai":"Đã truyền tới Lý Phủ và để lại cho Vương Lâm","blurb":"Chiếu chỉ do sứ giả thanh bào của Tiên Hoàng mang tới Lý Phủ, yêu cầu Vương Lâm dự đại lễ sắc phong Dược Thiên Tôn.","detail":"Ba ngày sau khi Vương Lâm lưu lại Lý Phủ, sứ giả thanh bào cầm tấm vải trắng xuất hiện trên bầu trời truyền ý chỉ của Tiên Hoàng. Nội dung chỉ yêu cầu Vương Lâm sáng sớm bảy ngày sau tới Tiên Đạo Điện trong hoàng cung để tiến hành đại lễ sắc phong Dược Thiên Tôn; sau khi đọc xong, sứ giả lưu lại thánh chỉ rồi rời đi.","nguon":["@c1870"]},{"id":"hac-giap-cua-cam-binh","name":"Hắc giáp của cấm binh","cn":"","aliases":["Hắc giáp cấm binh"],"category":"phap-bao","categoryLabel":"Khải giáp quân trang","phamCap":"không rõ","soHuu":["Hắc giáp cấm binh"],"trangThai":"đang dùng","blurb":"Áo giáp của mười vạn hắc giáp cấm binh trong hoàng cung Tiên Tộc. Nó có liên hệ lớn với sát khí cả đời của cấm binh và khiến Vương Lâm chú ý sau khi phá thông đạo cửu môn.","detail":"Hắc giáp gắn với sát khí của mười vạn cấm binh, giúp sát khí ấy ngưng tụ thành uy áp khảo nghiệm trong cửu môn. Sau khi Vương Lâm một quyền đánh tan hắc quang, toàn quân phun máu lui lại nhưng không ai chết, khiến hắn âm thầm chú ý tới áo giáp này.","phanLoaiPhu":"khải giáp quân đội","chuHienThoi":"Hắc giáp cấm binh","congNang":["Liên kết với sát khí cả đời của cấm binh để hình thành uy áp khảo nghiệm @c1871"],"dacDiem":"Sau khi thông đạo hắc quang bị đánh tan, cấm binh phun máu lui lại nhưng không ai tử vong, khiến áo giáp bị Vương Lâm chú ý.","chuSoHuu":[{"ten":"Hắc giáp cấm binh","tuChuong":"@c1871","denChuong":"","cachCoDuoc":"quân trang thuộc hoàng tộc","trangThai":"đang dùng"}],"capNhatToi":"@c1871","tabs":{"tienTrinh":[{"chuong":"@c1871","loai":"xuất hiện","importance":"normal","giaiDoan":"Khảo nghiệm cửu môn","text":"Hắc giáp của cấm binh được nêu là có liên hệ lớn với sát khí ngưng tụ thành uy áp, và sau cú đánh của Vương Lâm vẫn giúp toàn quân không tử vong.","anchor":"Luồng khí sát lục này là sát khí cả đời của mười vạn người này biến thành, có liên hệ rất lớn với hắc giáp của bọn họ"}]},"nguon":["@c1871"]},{"id":"hat-chau-mau-tim-cua-thuong-huyen-dao-quoc-su","name":"Hạt châu màu tím của Thượng Huyền Đạo quốc sư","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Thượng Huyền Đạo"],"trangThai":"đang thuộc Thượng Huyền Đạo","blurb":"Hạt châu màu tím xuất hiện trong tay Thượng Huyền Đạo khi hắn đứng cạnh Tiên Hoàng. Chương này chỉ nêu hình dáng và cách hắn cầm chuyển động trong lòng bàn tay, chưa hé lộ công năng trực tiếp.","detail":"Trong Tiên Đạo Điện, Thượng Huyền Đạo xuất hiện với dáng vẻ thanh niên áo vải thô, da trắng bệch, tay cầm hạt châu màu tím và không ngừng chuyển động nó trong lòng bàn tay.","phanLoaiPhu":"vật phẩm chưa rõ công năng","hinhDang":"hạt châu màu tím","dacDiem":"Được Thượng Huyền Đạo cầm trong tay khi lộ diện bên cạnh Tiên Hoàng.","chuHienThoi":"Thượng Huyền Đạo","chuSoHuu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1872","denChuong":"","cachCoDuoc":"xuất hiện trong tay khi đứng cạnh Tiên Hoàng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1872","loai":"xuất hiện","importance":"normal","giaiDoan":"Thượng Huyền Đạo lộ diện","text":"Hạt châu màu tím xuất hiện trong tay Thượng Huyền Đạo khi hắn đứng cạnh Tiên Hoàng trong Tiên Đạo Điện.","anchor":"cầm trong tay một hạt châu màu tím, không ngừng chuyển động trong lòng bàn tay hắn"}]},"capNhatToi":"@c1872","nguon":["@c1872"]},{"id":"soi-toc-bac-sau-thien-su-thu","name":"Sợi tóc bạc sau Thiên Sư Thú","category":"khac","categoryLabel":"Vật phẩm-bảo vật","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đoạt lấy","blurb":"Sợi tóc bạc còn lại sau khi Tiên Hoàng thiêu chết Thiên Sư Thú. Nó không bị Cực Hỏa Đạo đốt cháy, xuyên thủng bàn tay lửa năm màu của Tiên Hoàng và bị Vương Lâm đoạt lấy.","detail":"Sau khi biển lửa năm màu diệt Thiên Sư Thú tan đi, một sợi tóc bạc rơi xuống. Tiên Hoàng và Thượng Huyền Đạo đều kinh ngạc vì Cực Hỏa Đạo không thể đốt cháy nó; khi Tiên Hoàng dùng bàn tay lửa năm màu chụp lấy, sợi tóc xuyên thủng bàn tay ấy, khiến Vương Lâm lao lên đoạt lấy và cảm tạ như nhận bảo vật ban thưởng.","phanLoaiPhu":"vật phẩm-bảo vật kỳ dị","hinhDang":"sợi tóc bạc","dacDiem":"Không bị Cực Hỏa Đạo thiêu hủy và có thể xuyên thủng bàn tay lửa năm màu của Tiên Hoàng.","uyLuc":"Vượt qua một lần chụp bắt bằng lửa năm màu của Tiên Hoàng.","chuHienThoi":"Vương Lâm","congNang":["Không bị Cực Hỏa Đạo của Tiên Hoàng đốt cháy @c1872","Xuyên thủng bàn tay do lửa năm màu biến thành @c1872"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1872","denChuong":"","cachCoDuoc":"lao lên chụp lấy sau khi sợi tóc rơi xuống từ Thiên Sư Thú bị thiêu chết","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1872","loai":"đổi chủ","importance":"major","giaiDoan":"Sau khi Thiên Sư Thú bị diệt","text":"Sợi tóc bạc không bị Cực Hỏa Đạo đốt cháy, xuyên thủng bàn tay lửa năm màu của Tiên Hoàng và rơi vào tay Vương Lâm.","anchor":"Nhưng đúng lúc này bàn tay do ngọn lửa năm màu biến thành lại run lên, bị sợi tóc xuyên thấu"}]},"capNhatToi":"@c1872","nguon":["@c1872"]},{"id":"cot-am-dao-phap-bao","name":"Cốt âm đao","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"bị vỡ","blurb":"Cốt âm đao là vũ khí cận chiến bằng cốt của Vương Lâm, được sử dụng trong huyết chiến tại phố tuyết. Đao nứt vỡ khi va chạm với ngón tay bí ẩn, sau đó các mảnh vỡ được tái sử dụng làm nền trận pháp phản kim quang.","detail":"Vương Lâm dùng Cốt âm đao chém ba kẻ bị thương trên không và giao chiến với nhóm áo trắng, áo đen trong trận huyết chiến ở phố tuyết. Khi ngón tay bí ẩn điểm tới, Cốt âm đao va chạm rồi tan vỡ. Các mảnh đao sau đó được Vương Lâm dùng làm nền trận pháp phản chiếu kim quang nhằm phá giam cầm và đối chỉ.","phanLoaiPhu":"âm đao bằng cốt","hinhDang":"đao","chuHienThoi":"Vương Lâm","congNang":["Chém giết trong cận chiến @c1877","Sau khi vỡ, các mảnh đao được dùng làm nền trận pháp phản kim quang @c1877"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1877","denChuong":"","cachCoDuoc":"đã sử dụng trong huyết chiến phố tuyết","trangThai":"bị vỡ trong giao chiến"}],"tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Va chạm ngón tay bí ẩn","text":"Cốt âm đao của Vương Lâm nứt vỡ khi va chạm với ngón tay bí ẩn, rồi các mảnh đao được dùng làm trận pháp phản kim quang.","anchor":"thanh âm đao của Vương Lâm xuất hiện rất nhiều vết nứt, đột nhiên tan vỡ","phamCap":"chưa rõ"}]},"nguon":["@c1877"]},{"id":"hon-phong","name":"Hồn phong","cn":"","category":"khac","categoryLabel":"Ấn ban sức mạnh","phamCap":"chưa rõ","soHuu":["Hai Hồn khải sứ giả áo đen"],"trangThai":"đang sử dụng","blurb":"Vật hoặc ấn ban sức mạnh mà Vương Lâm suy đoán hai Dược Thiên Tôn áo đen xa lạ được trao cùng với việc bị nâng tu vi.","detail":"Khi nhận ra hai áo đen có sức mạnh Dược Thiên Tôn bất thường, Vương Lâm suy đoán họ không chỉ bị nâng tu vi mà còn được ban hồn phong. Khả năng này được hắn quy về quyền lực của Tiên Hoàng trong tổ thành.","phanLoaiPhu":"ấn ban sức mạnh","chuHienThoi":"Hai Hồn khải sứ giả áo đen","congNang":["Có thể được ban cùng thủ đoạn nâng sức mạnh lên cấp Dược Thiên Tôn @c1877"],"chuSoHuu":[{"ten":"Hai Hồn khải sứ giả áo đen","tuChuong":"@c1877","denChuong":"","cachCoDuoc":"được suy đoán là do Tiên Hoàng ban","trangThai":"đang sử dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"nhắc tới","importance":"normal","giaiDoan":"Suy luận về hai áo đen","text":"Vương Lâm suy đoán hai áo đen được ban hồn phong cùng với việc bị nâng tu vi.","anchor":"còn được ban cho hồn phong","phamCap":"chưa rõ"}]},"nguon":["@c1877"]},{"id":"manh-vo-cot-am-dao","name":"Mảnh vỡ cốt âm đao","cn":"","category":"khac","categoryLabel":"Vật phẩm / mảnh đao","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"vỡ tan","blurb":"Mảnh vỡ cốt âm đao được Vương Lâm dùng trong sát cục phố tuyết. Nó phản chiếu kim quang, hình thành trận pháp phóng đại lực phân thân hư vô rồi vỡ tan khi đánh vào ngón tay thần bí.","detail":"Trong lúc đối kháng ngón tay thần bí, Vương Lâm dùng mảnh vỡ cốt âm đao để phản chiếu kim quang và hình thành trận pháp trên mặt đao. Mảnh đao sau đó vỡ tan nhưng vẫn bắn tới ngón tay đang ngưng tụ lần thứ ba, khiến nó nổ thành nhiều mảnh.","phanLoaiPhu":"Mảnh đao","hinhDang":"Mảnh vỡ cốt đao","uyLuc":"Có thể phối hợp kim quang và lực phân thân trong hư vô để đánh ngón tay thần bí đang tái ngưng tụ.","congNang":["Phản chiếu kim quang trong mắt Vương Lâm.","Tạo trận pháp phóng đại lực phân thân trong hư vô.","Vỡ tan rồi bắn tới ngón tay đang ngưng tụ lần thứ ba."],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1878","denChuong":"@c1878","cachCoDuoc":"Đang nắm giữ khi ở trong sát cục phố tuyết","trangThai":"đã dùng và vỡ tan"}],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"dùng","importance":"normal","giaiDoan":"Đánh ngón tay tái hợp","text":"Vương Lâm dùng mảnh vỡ cốt âm đao tạo kim quang và trận pháp phóng đại lực phân thân hư vô, sau đó mảnh đao vỡ tan nhưng vẫn bắn vào ngón tay đang tái ngưng tụ.","anchor":"mảnh vỡ cốt đao tạo thành trận pháp liền lóe lên kim quang"}]},"capNhatToi":"@c1878","nguon":["@c1878"]},{"id":"cung-cua-tu-si","name":"Cung của tử sĩ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí / vũ khí","phamCap":"Không rõ","soHuu":["Gần trăm tử sĩ cầm cung trong phố tuyết"],"trangThai":"không rõ","blurb":"Cung do gần trăm tử sĩ trong phố tuyết cầm để tập kích Vương Lâm. Cung được dùng cùng tuyết, máu và sinh mạng tử sĩ để bắn ra mũi tên máu.","detail":"Gần trăm tử sĩ hiện ra trên mái nhà hai bên phố, trong tay đều cầm cung nhắm về phía Vương Lâm. Họ dùng gió tuyết ngưng tụ mũi tên, phun máu lên tên rồi tiêu hao sinh mạng để bắn đồng loạt.","phanLoaiPhu":"Vũ khí tầm xa","congNang":["Bắn mũi tên máu ngưng tụ bằng gió tuyết, máu và sinh mạng tử sĩ."],"chuSoHuu":[{"ten":"Gần trăm tử sĩ cầm cung trong phố tuyết","tuChuong":"@c1878","denChuong":"","cachCoDuoc":"Vũ khí mang theo khi hiện thân trong sát cục","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"dùng","importance":"normal","giaiDoan":"Bắn mũi tên máu","text":"Gần trăm tử sĩ dùng cung nhắm vào Vương Lâm rồi đổi máu và sinh mạng để bắn hơn trăm mũi tên máu.","anchor":"trong tay đều cầm một cây cung, nhắm về phía Vương Lâm"}]},"capNhatToi":"@c1878","nguon":["@c1878"]},{"id":"mui-ten-mau-mui-ten-tuyet-nhuom-mau","name":"Mũi tên máu / mũi tên tuyết nhuốm máu","cn":"","aliases":["Mũi tên máu","Mũi tên tuyết nhuốm máu"],"category":"khac","categoryLabel":"Vật phẩm công kích","phamCap":"Không rõ","soHuu":["Gần trăm tử sĩ cầm cung trong phố tuyết"],"trangThai":"phần lớn bị phá","blurb":"Hơn trăm mũi tên do tuyết và máu tử sĩ ngưng tụ trong sát cục phố tuyết. Phần lớn bị Tàn Dạ phá hủy, nhưng bảy mảnh vẫn xuyên qua thân thể Vương Lâm.","detail":"Các mũi tên được tử sĩ dùng tuyết ngưng tụ rồi phun máu lên, sau đó bắn đồng loạt về phía Vương Lâm với tốc độ khiến hắn khó né tránh. Tàn Dạ phá hủy phần lớn thế công, nhưng bảy mảnh tên không bị hủy diệt đã xuyên qua thân thể hắn.","phanLoaiPhu":"Mũi tên công kích","uyLuc":"Bảy mảnh tên còn sót lại xuyên qua thân thể Vương Lâm sau khi phần lớn mũi tên bị Tàn Dạ phá.","congNang":["Công kích đồng loạt từ nhiều vị trí bằng tốc độ cực nhanh.","Sau khi bị Tàn Dạ phá, bảy mảnh vẫn xuyên qua thân thể Vương Lâm."],"chuSoHuu":[{"ten":"Gần trăm tử sĩ cầm cung trong phố tuyết","tuChuong":"@c1878","denChuong":"@c1878","cachCoDuoc":"Ngưng tụ từ tuyết, máu và sinh mạng tử sĩ","trangThai":"đã bắn ra"}],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"dùng","importance":"normal","giaiDoan":"Xuyên thân Vương Lâm","text":"Hơn trăm mũi tên máu bắn vào Vương Lâm, phần lớn bị Tàn Dạ nghiền nát nhưng bảy mảnh vẫn xuyên qua thân thể hắn.","anchor":"hơn trăm mũi tên màu máu từ các vị trí bay thẳng về phía Vương Lâm"}]},"capNhatToi":"@c1878","nguon":["@c1878"]},{"id":"dau-chuong-an-tren-canh-tay-dao-phi","name":"Dấu chưởng ấn trên cánh tay Đạo Phi","cn":"","category":"khac","categoryLabel":"Dấu vết ký ức","phamCap":"Không rõ","soHuu":["Liên Đạo Phi"],"trangThai":"biến mất sau khi Tiên Hoàng ra tay","blurb":"Dấu chưởng ấn hiện lên trên cánh tay Đạo Phi khi ký ức về động phủ giới và Vương Lâm nới lỏng.","detail":"Khi Đạo Phi nhớ lại động phủ giới và Vương Lâm, trên cánh tay vốn nhẵn bóng của hắn chậm rãi hiện ra một dấu chưởng ấn giống vết một người từng nắm tay rất lâu. Sau khi Tiên Hoàng đặt tay lên vai Đạo Phi, dấu này biến mất cùng lúc Đạo Phi rơi vào mê man.","phanLoaiPhu":"Dấu vết gắn với ký ức","hinhDang":"Dấu chưởng ấn trên cánh tay","congNang":["Làm dấu hiệu bên ngoài cho quá trình ký ức Đạo Phi về động phủ giới và Vương Lâm trỗi dậy @c1881"],"dacDiem":"Xuất hiện khi ký ức nới lỏng và biến mất khi Tiên Hoàng can thiệp.","chuHienThoi":"Liên Đạo Phi","capNhatToi":"@c1881","chuSoHuu":[{"ten":"Liên Đạo Phi","tuChuong":"@c1881","denChuong":"@c1881","cachCoDuoc":"Tự hiện ra trên cánh tay khi ký ức nới lỏng","trangThai":"biến mất sau khi Tiên Hoàng đặt tay"}],"tabs":{"tienTrinh":[{"chuong":"@c1881","loai":"xuất hiện","importance":"normal","giaiDoan":"Ký ức trỗi dậy","text":"Dấu chưởng ấn hiện ra trên cánh tay Đạo Phi khi hắn nhớ lại động phủ giới và Vương Lâm, rồi biến mất sau khi Tiên Hoàng đặt tay khiến hắn mê man.","anchor":"lại có một dấu vết chưởng ấn đang chậm rãi hiển lộ ra"}]},"nguon":["@c1881"]},{"id":"ngoc-gian-uoc-dinh-song-tu-co-khai","name":"Ngọc giản ước định Song Tử - Cô Khai","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"tín vật ngọc giản","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"bị bóp vỡ","blurb":"Ngọc giản ước định Song Tử – Cô Khai là tín vật bảo chứng lời hứa giữa Vương Lâm với Song Tử Đại Thiên Tôn và Cô Khai Thiên Tôn. Khi bị bóp vỡ tại cửa đông Tổ Thành, ngọc giản hóa ánh sáng tím, dẫn ra trận pháp kỳ dị và triệu Song Tử Đại Thiên Tôn tới trợ giúp.","detail":"Vương Lâm mang ngọc giản này tới Tổ Thành như bảo chứng choước định với Song Tử Đại Thiên Tôn và Cô Khai Thiên Tôn. Dưới cửa đông Tổ Thành, hắn bóp nát ngọc giản; vật tức khắc hóa thành ánh sáng tím và hiện ra một trận pháp kỳ dị, qua đó Song Tử Đại Thiên Tôn xuất hiện thực hiện lời hứa (@c1882).","phanLoaiPhu":"tín vật ước định","hinhDang":"ngọc giản","chuHienThoi":"Vương Lâm","congNang":["Kích hoạt ước định giữa Vương Lâm với Song Tử Đại Thiên Tôn và Cô Khai Thiên Tôn (@c1882)","Khi bị bóp vỡ, hóa ánh sáng tím và dẫn ra trận pháp kỳ dị, triệu Song Tử Đại Thiên Tôn tới trợ giúp (@c1882)"],"dacDiem":"Sau khi bị bóp nát, ngọc giản hóa ánh sáng tím và dẫn ra trận pháp kỳ dị.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1882","denChuong":"@c1882","cachCoDuoc":"mang theo từ trước trong chuyến tới Tổ Thành","trangThai":"đã bóp vỡ để kích hoạt ước định"}],"capNhatToi":"@c1882","tabs":{"tienTrinh":[{"chuong":"@c1882","loai":"dùng","importance":"major","giaiDoan":"triệu Song Tử","text":"Vương Lâm bóp vỡ ngọc giản ước định dưới cửa đông Tổ Thành, kích hoạt ánh sáng tím và gọi Song Tử Đại Thiên Tôn tới giúp hắn.","anchor":"Trong nháy mắt khi ngọc giản bị bóp nát"}]},"nguon":["@c1882"]},{"id":"tieu-nhan-bach-quang-cua-quoc-su","name":"Tiểu nhân bạch quang của quốc sư","cn":"","category":"khac","categoryLabel":"Vật/thuật hình","phamCap":"không rõ","soHuu":["Thượng Huyền Đạo"],"trangThai":"bị bóp tan @c1883","blurb":"Tiểu nhân phát bạch quang xuất hiện trong lòng bàn tay quốc sư. Nó quỳ lạy rồi bay ra, phóng lớn thành thân ảnh tấn công Vương Lâm trước khi bị bóp tan.","detail":"Quốc sư lấy ra tiểu nhân bạch quang trong lòng bàn tay khi giải thích Đạo Diễn Hồn. Tiểu nhân quỳ lạy hắn rồi bay ra, hóa lớn thành thân ảnh lao tới Vương Lâm, nhưng bị Vương Lâm bắt lấy và vuốt tan.","hinhDang":"Tiểu nhân phát ra bạch quang @c1883","chuHienThoi":"Thượng Huyền Đạo","congNang":["Hóa thành thân ảnh tấn công Vương Lâm @c1883"],"chuSoHuu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1883","denChuong":"","cachCoDuoc":"Thi triển từ lòng bàn tay","trangThai":"đã dùng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1883","loai":"dùng","importance":"normal","giaiDoan":"Hóa thân ảnh tấn công","text":"Quốc sư cho tiểu nhân bạch quang bay ra, hóa thành thân ảnh lao tới Vương Lâm rồi bị Vương Lâm bóp tan.","anchor":"Chỉ thấy trong lòng bàn tay hắn có một tiều nhân phát ra bạch quang hiện ra."}]},"capNhatToi":"@c1883","nguon":["@c1883"]},{"id":"chin-soi-xich-sat-mau-nau","name":"Chín sợi xích sắt màu nâu","cn":"","category":"khac","categoryLabel":"Vật phong tỏa","phamCap":"không rõ","soHuu":["Hoàng cung Tiên Tộc"],"trangThai":"đang phong tỏa Liên Đạo Phi @c1883","blurb":"Chín sợi xích sắt màu nâu nằm quanh tế đàn địa cung. Chúng xuyên qua toàn thân người điên, treo giữ hắn trong trạng thái hôn mê.","detail":"Trong địa cung, quanh tế đàn có chín cây cột và chín sợi xích sắt màu nâu. Các xích xuyên qua toàn thân người điên, khiến hắn bị treo lơ lửng phía trên tế đàn và hôn mê bất tỉnh.","hinhDang":"Chín sợi xích sắt màu nâu @c1883","congNang":["Trói và xuyên giữ Liên Đạo Phi phía trên tế đàn địa cung @c1883"],"chuHienThoi":"Hoàng cung Tiên Tộc","chuSoHuu":[{"ten":"Hoàng cung Tiên Tộc","tuChuong":"@c1883","denChuong":"","cachCoDuoc":"Bố trí trong địa cung","trangThai":"đang dùng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1883","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong tỏa người điên","text":"Chín sợi xích sắt màu nâu xuyên qua toàn thân người điên và treo giữ hắn hôn mê phía trên tế đàn.","anchor":"toàn thân bị chín sợi xích kia xỏ qua, hôn mê bất tỉnh"}]},"capNhatToi":"@c1883","nguon":["@c1883"]},{"id":"ao-mau-truyen-thua","name":"Ao máu truyền thừa","cn":"","category":"khac","categoryLabel":"Vật phẩm nghi thức","phamCap":"không rõ","soHuu":["Tiên Hoàng"],"trangThai":"đang dùng","blurb":"Ao máu trước tế đàn là trọng điểm trong kế phản tổ và truyền thừa do các đời Tiên Hoàng chuẩn bị.","detail":"Quốc sư nói ao máu là trọng điểm của chuyện phản tổ, do nhiều đời Tiên Hoàng chuẩn bị. Minh Đạo Tôn đang ngồi trong ao này để tăng khả năng phản cổ thành công.","phanLoaiPhu":"nghi thức truyền thừa","hinhDang":"ao máu","nguonGoc":"Do nhiều đời Tiên Hoàng chuẩn bị","congNang":["Tăng khả năng phản cổ và truyền thừa @c1884"],"chuHienThoi":"Tiên Hoàng","dinhDanh":"goc","nguon":["@c1884"],"tabs":{"tienTrinh":[{"chuong":"@c1884","loai":"xuất hiện","importance":"normal","giaiDoan":"Trọng điểm phản tổ","text":"Quốc sư chỉ ra ao máu trước tế đàn là trọng điểm trong thủ đoạn của Tiên Hoàng, nơi Minh Đạo Tôn đang ngồi để thúc đẩy phản tổ.","anchor":"Vật này rất khó có được, là do nhiều đời Tiên Hoàng chuẩn bị","phamCap":"không rõ"}]}},{"id":"menh-tinh-cua-toc-quoc-su","name":"Mệnh tinh của tộc quốc sư","cn":"","category":"khac","categoryLabel":"Tinh thạch bản mệnh","phamCap":"không rõ","soHuu":["Vương Lâm","Thượng Huyền Đạo"],"trangThai":"đã giao cho Vương Lâm","blurb":"Tinh thạch màu đen là mệnh tinh của tộc quốc sư, được quốc sư tự tay lấy ra khỏi thân thể và giao cho Vương Lâm làm vật gửi gắm lòng tin.","detail":"Mệnh tinh là vật bản mệnh gắn liền với sinh lực của tộc quốc sư. Quốc sư chủ động rút tinh thạch đen ra khỏi cơ thể mình rồi trao cho Vương Lâm nhằm chứng tỏ sự thành tâm. Ngay sau khi mất mệnh tinh, quốc sư lập tức suy kiệt, thân thể già nua, thời gian sống không còn bao lâu.","phanLoaiPhu":"mệnh tinh","hinhDang":"tinh thạch màu đen","congNang":["Là vật bản mệnh của tộc quốc sư, gắn trực tiếp với sinh lực của chủ nhân @c1884","Được dùng làm bằng chứng giao phó lòng tin cho Vương Lâm @c1884"],"dacDiem":"Mất đi mệnh tinh khiến quốc sư lập tức suy kiệt, thân thể già nua và không còn sống được bao lâu.","chuHienThoi":"Vương Lâm","dinhDanh":"goc","nguon":["@c1884"],"chuSoHuu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1884","denChuong":"@c1884","cachCoDuoc":"Mệnh tinh của tộc hắn nằm trong thân thể hắn.","trangThai":"đã giao đi"},{"ten":"Vương Lâm","tuChuong":"@c1884","denChuong":"","cachCoDuoc":"Được quốc sư giao để lấy lòng tin.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1884","loai":"đổi chủ","importance":"major","giaiDoan":"Quốc sư giao mệnh tinh","text":"Quốc sư lấy tinh thạch đen là mệnh tinh của tộc mình giao cho Vương Lâm, khiến bản thân già nua và không còn nhiều thời gian.","anchor":"sau khi mất đi thời gian của ta không còn nhiều lắm","phamCap":"không rõ"}]}},{"id":"trung-tam-huong-hoa-cua-dong-phu-gioi","name":"Trung tâm hương hỏa của động phủ giới","cn":"","category":"khac","categoryLabel":"Nguồn hương hỏa","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"trong người Vương Lâm","blurb":"Vật trong người Vương Lâm nhận hương hỏa lực từ tất cả động phủ giới trên Tiên Cương đại lục.","detail":"Quốc sư nói trong người Vương Lâm có trung tâm hương hỏa do tất cả động phủ giới trên Tiên Cương đại lục cung cấp. Vì Vương Lâm sinh ra từ động phủ giới, linh hồn và thân thể hắn có thể trực tiếp hấp thu hương hỏa ấy.","phanLoaiPhu":"nguồn hương hỏa","congNang":["Liên tục truyền hương hỏa lực cho Vương Lâm @c1884"],"chuHienThoi":"Vương Lâm","dinhDanh":"goc","nguon":["@c1884"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1884","denChuong":"","cachCoDuoc":"Tồn tại trong người hắn và nhận hương hỏa từ động phủ giới.","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1884","loai":"nhắc tới","importance":"normal","giaiDoan":"Hương hỏa truyền liên tục","text":"Quốc sư nói vật trong người Vương Lâm là trung tâm hương hỏa, liên tục nhận hương hỏa lực từ các động phủ giới trên Tiên Cương đại lục.","anchor":"không lúc nào không có hương hỏa lực truyền cho ngươi","phamCap":"không rõ"}]}},{"id":"chin-soi-xich-sat-tren-te-dan","name":"Chín sợi xích sắt trên tế đàn","cn":"","category":"phap-bao","categoryLabel":"Phong ấn / vật khóa","phamCap":"không rõ","soHuu":["Thượng Huyền Đạo"],"trangThai":"đang dùng","blurb":"Chín sợi xích khóa Liên Đạo Phi trên tế đàn trong địa cung.","detail":"Chín sợi xích sắt phong tỏa Liên Đạo Phi trên tế đàn. Khi Vương Lâm tới gần để cứu người, kim quang quanh khu vực này bộc phát khiến hắn kinh hãi và bị đẩy lui; quốc sư cho biết Tiên Hoàng đã biết việc xích sắt bị động tới.","congNang":["Phong tỏa Liên Đạo Phi trên tế đàn và liên quan tới kim quang bài xích Vương Lâm @c1885"],"chuSoHuu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1885","denChuong":"","cachCoDuoc":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1885","loai":"dùng","importance":"normal","giaiDoan":"Phong tỏa Liên Đạo Phi","text":"Chín sợi xích khóa Liên Đạo Phi trên tế đàn, khiến Vương Lâm bị kim quang bức lui khi tới gần cứu người.","anchor":"Đồng tử trong hai mắt Vương Lâm co rút lại, lùi lại phía sau, trong ánh mắt nhìn về xích sắt bên ngoài thân thể người điên lộ ra vẻ kinh hãi"}]},"capNhatToi":"@c1885","nguon":["@c1885"]},{"id":"truyen-thua-cua-tien-to-trong-minh-dao-ton","name":"Truyền thừa của Tiên Tổ trong Minh Đạo Tôn","cn":"","category":"khac","categoryLabel":"Truyền thừa / quầng sáng vàng","phamCap":"không rõ","soHuu":["Minh Đạo Tôn"],"trangThai":"đang tranh đoạt","blurb":"Truyền thừa của Tiên Tổ là di sản ẩn trong thân thể Minh Đạo Tôn, lộ ra dưới dạng quầng sáng vàng cỡ nắm tay khi huyết nhục tan hết chỉ còn xương đen. Quốc sư mưu đồ chuyển truyền thừa này sang Vương Lâm thông qua Phản tổ đại pháp.","detail":"Truyền thừa Tiên Tổ nằm sâu trong thân thể Minh Đạo Tôn, chỉ hiện hình khi huyết nhục nổ hết và thân xác chỉ còn lại bộ xương đen. Nó biểu hiện thành một quầng sáng vàng cỡ nắm tay. Quốc sư cóý định dùng Phản tổ đại pháp để tách truyền thừa này khỏi Minh Đạo Tôn và chuyển cho Vương Lâm; sau khi thân thể Minh Đạo Tôn tan nát, quốc sư dùng u quang lao tới quầng sáng.","phanLoaiPhu":"truyền thừa huyết mạch","hinhDang":"quầng sáng màu vàng kim cỡ nắm tay","dacDiem":"Nằm trong thân thể xương đen của Minh Đạo Tôn, biểu hiện dưới dạng quầng sáng vàng cỡ nắm tay khi huyết nhục đã tan hết.","chuHienThoi":"Minh Đạo Tôn","congNang":["Liên quan trực tiếp tới Phản tổ đại pháp, có thể được chuyển giao giữa các thể xác @c1886"],"chuSoHuu":[{"ten":"Minh Đạo Tôn","tuChuong":"@c1886","denChuong":"","cachCoDuoc":"nhận truyền thừa Tiên Tổ","trangThai":"đang giữ trong cơ thể"}],"tabs":{"tienTrinh":[{"chuong":"@c1886","loai":"xuất hiện","importance":"major","giaiDoan":"lộ hình dạng","text":"Truyền thừa Tiên Tổ lộ rõ thành quầng sáng vàng cỡ nắm tay trong thân thể chỉ còn xương đen của Minh Đạo Tôn.","anchor":"Quầng sáng này chính là truyền thừa của Tiên Tổ mà hắn nhận được"}]},"capNhatToi":"@c1886","nguon":["@c1886"]},{"id":"kim-quang-trong-co-the-minh-dao-ton","name":"Kim quang trong cơ thể Minh Đạo Tôn","cn":"","category":"khac","categoryLabel":"Lực lượng / truyền thừa","phamCap":"không rõ","soHuu":["Minh Đạo Tôn"],"trangThai":"đang phát tác","blurb":"Kim quang ăn mòn thân thể Minh Đạo Tôn và thúc đẩy biến hóa Phản tổ đại pháp.","detail":"Kim quang khiến thân thể Minh Đạo Tôn thối rữa, bức lui hoặc thay thế thần thông pháp bảo, làm huyết nhục và xương cốt hắn diễn biến theo quá trình Phản tổ đại pháp.","phanLoaiPhu":"lực lượng truyền thừa","dacDiem":"Không gì phá nổi trong cơ thể Minh Đạo Tôn khi pháp đang phát tác.","chuHienThoi":"Minh Đạo Tôn","uyLuc":"Có thể bức lui thần thông pháp bảo và chi phối quá trình bóc tách huyết nhục, tan nát xương cốt.","congNang":["Ăn mòn thân thể Minh Đạo Tôn và thúc đẩy quá trình Phản tổ đại pháp @c1886"],"chuSoHuu":[{"ten":"Minh Đạo Tôn","tuChuong":"@c1886","denChuong":"","cachCoDuoc":"phát sinh từ truyền thừa Tiên Tổ trong cơ thể","trangThai":"đang phát tác"}],"tabs":{"tienTrinh":[{"chuong":"@c1886","loai":"xuất hiện","importance":"normal","giaiDoan":"ăn mòn Minh Đạo Tôn","text":"Kim quang trong cơ thể Minh Đạo Tôn ăn mòn thân thể hắn và bức lui thần thông pháp bảo trong quá trình Phản tổ đại pháp.","anchor":"kim quang trong cơ thể hắn lại không gì phá nổi"}]},"capNhatToi":"@c1886","nguon":["@c1886"]},{"id":"dom-sang-mau-vang-cua-minh-dao-ton","name":"Đốm sáng màu vàng của Minh Đạo Tôn","cn":"","category":"khac","categoryLabel":"Hào quang / hạt nhân ngưng tụ","phamCap":"không rõ","soHuu":["Minh Đạo Tôn"],"trangThai":"bị hút vào mắt phải Tiên Tổ","blurb":"Đốm sáng vàng còn lại sau khi Minh Đạo Tôn tan nát huyết nhục và xương cốt. Nó là hạt nhân giúp ngưng tụ thân thể nhưng sau đó bị mắt phải đầu Tiên Tổ hút vào.","detail":"Tại nơi Minh Đạo Tôn tiêu tán xuất hiện một hào quang vàng cỡ nắm tay, bên trong dần ngưng tụ lại thân ảnh Minh Đạo Tôn. Sau khi thân ảnh vàng bị Vương Lâm đánh sụp, đốm sáng này không bị tổn thương, bay lên trời rồi đổi hướng nhập vào mắt phải đầu Tiên Tổ.","phanLoaiPhu":"hào quang ngưng tụ thân thể","hinhDang":"đốm sáng màu vàng cỡ nắm tay","chuHienThoi":"Minh Đạo Tôn","dacDiem":"Không bị tổn thương khi thân ảnh vàng bị đánh sụp.","congNang":["Ngưng tụ lại thân thể Minh Đạo Tôn @c1887","Bị mắt phải đầu Tiên Tổ hút vào làm một phần của nghi thức trong mắt phải @c1887"],"chuSoHuu":[{"ten":"Minh Đạo Tôn","tuChuong":"@c1887","denChuong":"","cachCoDuoc":"hạt nhân còn lại sau Phản Tổ Đại Pháp","trangThai":"bị hút vào mắt phải Tiên Tổ"}],"capNhatToi":"@c1887","tabs":{"tienTrinh":[{"chuong":"@c1887","loai":"xuất hiện","importance":"normal","giaiDoan":"Hạt nhân kim quang","text":"Đốm sáng màu vàng của Minh Đạo Tôn hiện ra sau khi thân thể hắn tiêu tán, không bị thương tổn khi thân ảnh vàng bị đánh sụp và bị hút vào mắt phải đầu Tiên Tổ.","anchor":"nhưng đốm sáng màu vàng này cũng không bị thương tổn một chút nào"}]},"nguon":["@c1887"]},{"id":"dau-tien-to-lien-van-quyet","name":"Đầu Tiên Tổ Liên Vân Quyết","aliases":["Đầu lâu Tiên Tổ","Cái đầu tiên tổ","Đầu Tiên Tổ"],"cn":"","category":"khac","categoryLabel":"Di hài / đầu lâu","phamCap":"không rõ","soHuu":["Tiên Tổ Liên Vân Quyết","Thượng Huyền Đạo"],"trangThai":"được triệu hồi, mắt phải mở ra","blurb":"Đầu của Tiên Tổ Liên Vân Quyết là bộ phận bị xé khỏi thân thể, được giấu bên trong ngọn núi có hình dáng đầu Tiên Tổ. Khi quốc sư triệu hồi, nó tỏa uy áp kinh thiên động địa rồi mở mắt phải hút đốm sáng vàng của Minh Đạo Tôn và hút luôn Vương Lâm vào trong.","detail":"Đầu Tiên Tổ Liên Vân Quyết lộ diện khi quốc sư chỉ xuống ngọn núi hình đầu và gọi Tiên Tổ. Cái đầu còn nguyên mặt mũi, tóc dài mười trượng, thất khiếu có vết máu vàng ngả tím, cổ mang vết thương như bị xé đứt khỏi thân thể. Uy áp của nó vừa xuất hiện đã khiến Vương Lâm cảm thấy thân thể bị chèn ép và linh hồn như muốn tan rã. Sau đó mắt phải mở ra, bộc phát kim quang hút đốm sáng vàng của Minh Đạo Tôn rồi hút cả Vương Lâm vào bên trong.","phanLoaiPhu":"di hài Tiên Tổ","hinhDang":"đầu lâu còn nguyên mặt mũi, tóc dài mười trượng, thất khiếu có vết máu vàng ngả tím","nguonGoc":"đầu của Tiên Tổ Liên Vân Quyết","chuHienThoi":"Thượng Huyền Đạo","dacDiem":"Đầu bị xé khỏi thân thể, còn nguyên mặt mũi, tóc dài mười trượng, thất khiếu có vết máu vàng ngả tím, được giấu trong ngọn núi có hình dáng đầu Tiên Tổ.","uyLuc":"Uy áp xuất hiện đủ khiến Vương Lâm bị chèn ép thân thể và linh hồn như muốn tan rã.","congNang":["Mắt phải hút đốm sáng màu vàng của Minh Đạo Tôn @c1887","Mắt phải bộc phát kim quang hút Vương Lâm vào trong @c1887"],"chuSoHuu":[{"ten":"Tiên Tổ Liên Vân Quyết","tuChuong":"@c1887","denChuong":"","cachCoDuoc":"di hài bản thân","trangThai":"bị tách khỏi thân thể"},{"ten":"Thượng Huyền Đạo","tuChuong":"@c1887","denChuong":"","cachCoDuoc":"triệu hồi từ ngọn núi hình đầu","trangThai":"dùng làm trung tâm nghi thức truyền thừa và đoạt thân"}],"capNhatToi":"@c1887","tabs":{"tienTrinh":[{"chuong":"@c1887","loai":"xuất hiện","importance":"major","giaiDoan":"Đầu Tiên Tổ xuất thế","text":"Quốc sư triệu hồi đầu Tiên Tổ từ trong ngọn núi hình đầu, khiến nó tỏa uy áp kinh thiên động địa rồi mở mắt phải hút đốm sáng vàng và Vương Lâm vào trong.","anchor":"Cái đầu này xuất hiện liền có một uy áp đủ để kinh thiên động địa"}]},"nguon":["@c1887"]},{"id":"hon-huyet-co-to-cua-vuong-lam","name":"Hồn huyết Cổ Tổ của Vương Lâm","cn":"","category":"khac","categoryLabel":"Huyết mạch","phamCap":"Ngang hàng truyền thừa tu vi của Tiên Tổ","soHuu":["Vương Lâm"],"trangThai":"đang tồn tại trong thân thể Vương Lâm","blurb":"Hồn huyết Cổ Tổ nằm trong cơ thể Vương Lâm, là biến số chống lại kim quang truyền thừa Tiên Tổ.","detail":"Khi kim quang truyền thừa Tiên Tổ chiếm gần toàn bộ thân thể Vương Lâm, vị trí chứa hồn huyết Cổ Tổ vẫn không bị thay đổi. Thượng Huyền Đạo không thể xóa bỏ nó, chỉ có thể dùng kim quang bao vây và giam cầm khu vực này.","phanLoaiPhu":"huyết mạch trong thân","dacDiem":"Tồn tại ngang hàng với truyền thừa tu vi của Tiên Tổ, khiến kim quang không thể lấn át hoàn toàn.","congNang":["Chống lại sự xâm chiếm hoàn toàn của kim quang truyền thừa Tiên Tổ trong thân thể Vương Lâm @c1888"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1888","denChuong":"","cachCoDuoc":"đã tồn tại trong thân thể","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1888","loai":"nhắc tới","importance":"normal","giaiDoan":"Chống kim quang","text":"Hồn huyết Cổ Tổ trong thân thể Vương Lâm khiến kim quang truyền thừa Tiên Tổ không thể xâm chiếm hoàn toàn.","anchor":"kim quang có xâm nhập thế nào cũng mãi không thể thay đổi được"}]},"capNhatToi":"@c1888","nguon":["@c1888"]},{"id":"thien-thach-mau-tim","name":"Thiên thạch màu tím","cn":"","category":"khac","categoryLabel":"Hiện tượng thần thông","phamCap":"Không rõ","soHuu":["Song Tử Đại Thiên Tôn"],"trangThai":"được triệu xuống","blurb":"Thiên thạch tím khổng lồ xuất hiện khi Song Tử thi triển Tử Lâm Tín Thuật.","detail":"Thiên thạch màu tím lớn bằng nửa tổ thành xuất hiện trên bầu trời Tiên Cương Đại Lục, tạo uy áp khiến tổ thành chấn động, mặt đất nứt vỡ và tu sĩ bỏ chạy.","uyLuc":"Uy hiếp phá nát tổ thành nếu Tiên hoàng không giao Vương Lâm.","congNang":["Tạo sức ép phá hủy quy mô tổ thành trong Tử Lâm Tín Thuật @c1889"],"chuSoHuu":[{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1889","denChuong":"","cachCoDuoc":"Dẫn xuống bằng Tử Lâm Tín Thuật","trangThai":"được triệu xuống"}],"tabs":{"tienTrinh":[{"chuong":"@c1889","loai":"xuất hiện","importance":"normal","giaiDoan":"Tử Lâm Tín Thuật","text":"Thiên thạch màu tím khổng lồ được Song Tử dẫn xuống để uy hiếp phá nát tổ thành.","anchor":"một thiên thạch màu tím khổng lồ có thể so với một nửa tổ thành"}]},"dinhDanh":"goc","capNhatToi":"@c1889","nguon":["@c1889"]},{"id":"thanh-kiem-mau-vang-cua-hu-anh-tien-to","name":"Thanh kiếm màu vàng của hư ảnh Tiên Tổ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Kiếm / thần thông hóa vật","phamCap":"Không rõ","soHuu":["Tiên Tổ","Tiên Hoàng"],"trangThai":"bị phá tan @c1890","blurb":"Thanh kiếm vàng do hư ảnh Tiên Tổ chộp hư không biến ra trong trận chiến ở cấm cung.","detail":"Thanh kiếm được Tiên Hoàng dẫn qua hư ảnh Tiên Tổ, từng được gợi lại là một kiếm có thể khiến nhiều sinh linh thiên ngoại hình thần câu diệt. Trong hiện tại, nó chỉ chứa một thành lực lượng Tiên Tổ nhưng vẫn buộc bốn Đại Thiên Tôn hợp lực phá tan.","hinhDang":"Thanh kiếm màu vàng","uyLuc":"Một thành lực lượng Tiên Tổ cũng đủ đẩy lui bốn Đại Thiên Tôn trước khi bị phá.","congNang":["Chém xuống bằng lực lượng hư ảnh Tiên Tổ @c1890","Tạo lời kêu gọi sâu đối với Vương Lâm đang ẩn trong mắt phải đầu lâu Tiên Tổ @c1890"],"chuSoHuu":[{"ten":"Tiên Tổ","tuChuong":"@c1890","denChuong":"@c1890","cachCoDuoc":"hư ảnh chộp hư không biến ra","trangThai":"hóa vật"},{"ten":"Tiên Hoàng","tuChuong":"@c1890","denChuong":"@c1890","cachCoDuoc":"dẫn hư ảnh Tiên Tổ bằng máu","trangThai":"điều động"}],"tabs":{"tienTrinh":[{"chuong":"@c1890","loai":"xuất hiện","importance":"normal","giaiDoan":"Kim kiếm hiện hình","text":"Hư ảnh Tiên Tổ chộp hư không biến ra thanh kiếm vàng, thanh kiếm chém xuống rồi bị bốn Đại Thiên Tôn hợp lực phá tan.","anchor":"Bất ngờ một thanh kiếm màu vàng biến ảo ra","phamCap":"Không rõ"}]},"capNhatToi":"@c1890","nguon":["@c1890"]},{"id":"hai-tai-tien-to","name":"Hai tai Tiên Tổ","aliases":["hai tai của Tiên Tổ"],"cn":"","category":"khac","categoryLabel":"Bộ phận Tiên Tổ / vật nhập đạo","phamCap":"không rõ","soHuu":["Võ Phong Đại Thiên Tôn"],"trangThai":"được Cửu Đế hứa giao cho Vũ Phong","blurb":"Hai tai Tiên Tổ là bộ phận được Cửu Đế hứa cho Vũ Phong. Chúng gắn với khả năng thính đạo, nghe quỹ tích phép tắc Tiên Cương.","detail":"Trong phần chia lợi ích từ thi thể Tiên Tổ, Cửu Đế nói hai tai Tiên Tổ dành cho Vũ Phong. Nếu dung nhập vào đạo, chúng có thể giúp cảm thụ quỹ tích vận chuyển phép tắc Tiên Cương.","phanLoaiPhu":"bộ phận Tiên Tổ","uyLuc":"Có thể hỗ trợ nghe quỹ tích phép tắc Tiên Cương.","congNang":["Thính đạo, nghe quỹ tích phép tắc Tiên Cương @c1892"],"chuSoHuu":[{"ten":"Võ Phong Đại Thiên Tôn","tuChuong":"@c1892","denChuong":"","cachCoDuoc":"được Cửu Đế hứa giao","trangThai":"dự kiến nhận"}],"tabs":{"tienTrinh":[{"chuong":"@c1892","loai":"xuất hiện","importance":"normal","giaiDoan":"Được hứa cho Vũ Phong","text":"Cửu Đế nêu hai tai Tiên Tổ là phần lợi ích dành cho Vũ Phong trong kế hoạch xử lý thi thể Tiên Tổ.","anchor":"Vũ Phong, hai tai của Tiên Tổ"}]},"capNhatToi":"@c1892","nguon":["@c1892"]},{"id":"nao-tien-to","name":"Não Tiên Tổ","cn":"","category":"khac","categoryLabel":"Bộ phận Tiên Tổ","phamCap":"không rõ","soHuu":["Cửu Đế Đại Thiên Tôn"],"trangThai":"được Cửu Đế dự tính lấy","blurb":"Não Tiên Tổ là phần Cửu Đế tuyên bố muốn lấy cho riêng mình. Công dụng cụ thể chưa được giải thích, chỉ được nói là rất hữu dụng với hắn.","detail":"Khi chia lợi ích từ thi thể Tiên Tổ, Cửu Đế nói thứ hắn muốn chính là não Tiên Tổ. Hắn không nói rõ công dụng, nhưng đặt nó ngang hàng với mắt, tai, đầu và tu vi Tiên Tổ trong cuộc phân chia.","phanLoaiPhu":"bộ phận Tiên Tổ","congNang":["Cửu Đế nói não Tiên Tổ hữu dụng với hắn nhưng chưa nói rõ công dụng @c1892"],"chuSoHuu":[{"ten":"Cửu Đế Đại Thiên Tôn","tuChuong":"@c1892","denChuong":"","cachCoDuoc":"dự tính lấy sau khi ép Tiên hoàng phá trớ thuật","trangThai":"dự kiến chiếm lấy"}],"tabs":{"tienTrinh":[{"chuong":"@c1892","loai":"xuất hiện","importance":"normal","giaiDoan":"Cửu Đế chọn phần","text":"Cửu Đế tuyên bố phần hắn muốn trong thi thể Tiên Tổ là não Tiên Tổ.","anchor":"Thứ mà lão phu muốn chính là não của Tiên Tổ"}]},"capNhatToi":"@c1892","nguon":["@c1892"]},{"id":"tu-vi-tien-toc-cua-tien-to","name":"Tu vi tiên tộc của Tiên Tổ","cn":"","category":"khac","categoryLabel":"Truyền thừa / lực lượng","phamCap":"không rõ","soHuu":[],"trangThai":"được Cửu Đế dự tính chia đều","blurb":"Tu vi tiên tộc của Tiên Tổ là phần lực lượng được Cửu Đế nêu trong cuộc chia lợi ích. Hắn nói phần này sẽ được chia đều sau khi xử lý đầu Tiên Tổ.","detail":"Bên cạnh mắt, tai, đầu và não Tiên Tổ, Cửu Đế còn nhắc tới tu vi tiên tộc của Tiên Tổ. Phần tu vi này theo lời hắn sẽ được chia đều giữa các bên tham dự.","phanLoaiPhu":"truyền thừa lực lượng","congNang":["Có thể được chia như phần tu vi tiên tộc của Tiên Tổ @c1892"],"tabs":{"tienTrinh":[{"chuong":"@c1892","loai":"xuất hiện","importance":"normal","giaiDoan":"Đưa vào phân chia","text":"Cửu Đế nói tu vi tiên tộc của Tiên Tổ sẽ được chia đều giữa các bên.","anchor":"Còn về tu vi của tiên tộc kia chúng ta.sẽ chia đều"}]},"capNhatToi":"@c1892","nguon":["@c1892"]},{"id":"linh-hon-tien-hoang-bi-thu-giu","name":"Linh hồn Tiên Hoàng bị thu giữ","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh hồn/tù vật","phamCap":"Đại Thiên Tôn","soHuu":["Vương Lâm"],"trangThai":"bị thu vào không gian trữ vật","blurb":"Linh hồn còn lại của Tiên Hoàng sau khi tự bạo thân thể, bị Vương Lâm thu giữ trước khi kịp đoạt xá Liên Đạo Phi.","detail":"Sau vụ tự bạo, linh hồn Tiên Hoàng suy yếu vì hao tổn và Trớ Thuật. Khi hắn định nhập vào thân thể Liên Đạo Phi, Vương Lâm vung tay áo hút tới, túm lấy và thu vào không gian trữ vật. Tại thời điểm ghi nhận, linh hồn này đang ở trạng thái tù vật trongay Vương Lâm.","phanLoaiPhu":"Linh hồn tù vật","nguonGoc":"Linh hồn Tiên Hoàng còn lại sau khi tự bạo thân thể.","chuHienThoi":"Vương Lâm","congNang":["Có thể bị dùng làm tù vật hoặc đối tượng xử trí sau khi Vương Lâm thu giữ @c1893"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1893","denChuong":"","cachCoDuoc":"Thu giữ sau khi chặn Tiên Hoàng đoạt xá Liên Đạo Phi","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1893","loai":"đổi chủ","importance":"major","giaiDoan":"Bị Vương Lâm thu giữ","text":"Linh hồn Tiên Hoàng suy yếu sau tự bạo và Trớ Thuật, bị Vương Lâm hút tới rồi thu vào không gian trữ vật.","anchor":"cuối cùng bị Vương Lâm túm lấy, thu vào trong không gian trữ vật"}]},"capNhatToi":"@c1893","nguon":["@c1893"]},{"id":"hai-con-nguoi-tien-to","name":"Hai con ngươi Tiên Tổ","cn":"","category":"khac","categoryLabel":"Di hài trọng vật","phamCap":"Di hài Tiên Tổ","soHuu":["Song Tử Đại Thiên Tôn"],"trangThai":"đã-trao-cho-song-tử","blurb":"Hai con ngươi được chấn ra từ đầu lâu Tiên Tổ khi Vương Lâm đạp nát, dính tàn huyết vàng kim. Vương Lâm trao chúng cho Song Tử Đại Thiên Tôn giữa cuộc tranh đoạt vì vật này có tác dụng với họ.","detail":"Trong cuộc giao tranh tại nơi đầu lâu Tiên Tổ hiện diện, Vương Lâm đạp mạnh khiến hai mắt đầu lâu nổ tung, chấn ra hai con ngươi còn dính tàn huyết vàng kim. Nhận định vật này có tác dụng với Song Tử Đại Thiên Tôn, Vương Lâm lập tức giao lại cho họ nhằm đáp lại sự tương trợ trước đó.","phanLoaiPhu":"Dị vật từ di hài Tiên Tổ","hinhDang":"Hai con ngươi dính tàn huyết vàng kim","chuHienThoi":"Song Tử Đại Thiên Tôn","congNang":["Có tác dụng với Song Tử Đại Thiên Tôn @c1894"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1894","denChuong":"@c1894","cachCoDuoc":"Chấn ra từ đầu lâu Tiên Tổ","trangThai":"đã-trao"},{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1894","denChuong":"","cachCoDuoc":"Được Vương Lâm trao","trangThai":"đang-giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1894","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm trao cho Song Tử","text":"Vương Lâm chấn hai con ngươi khỏi đầu lâu Tiên Tổ rồi giao cho Song Tử Đại Thiên Tôn.","anchor":"hai con ngươi của Tiên Tổ, sắc mặt tuy rằng tái nhợt"}]},"capNhatToi":"@c1894","nguon":["@c1894"],"dacDiem":"Hai con ngươi lấy từ đầu lâu Tiên Tổ, còn dính tàn huyết vàng kim"},{"id":"dau-lau-tre-con-tran-ngap-tu-khi","name":"Đầu lâu trẻ con tràn ngập tử khí","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đoạt được từ Đạo Nhất @c1896","blurb":"Đầu lâu nhỏ như của trẻ con, tràn ngập tử khí và gợi cảm giác quen thuộc rõ rệt trong tâm thần Vương Lâm. Nó bị Đạo Nhất giao ra dưới sức ép của Vương Lâm và Cửu Đế.","detail":"Đạo Nhất lấy ra đầu lâu nhỏ bằng nắm tay trong lúc bị ép vào đường cùng. Vật này tràn ngập tử khí cuốn động hư vô, khiến Vương Lâm lập tức cảm thấy quen thuộc trong tâm thần, rồi trở thành cái giá để Đạo Nhất được tha mạng và phá hư vô trốn đi.","phanLoaiPhu":"Dị bảo dạng đầu lâu","hinhDang":"Đầu lâu nhỏ như của trẻ con","uyLuc":"Tử khí lan tràn dung nhập hư vô và cuốn động tám phương.","dacDiem":"Gợi cảm giác quen thuộc rõ ràng trong tâm thần Vương Lâm.","chuHienThoi":"Vương Lâm","congNang":["Tỏa tử khí mạnh mẽ, dung nhập hư vô và cuốn động tám phương @c1896","Gợi cảm giác quen thuộc rõ ràng trong tâm thần Vương Lâm @c1896"],"chuSoHuu":[{"ten":"Đạo Nhất","tuChuong":"@c1896","denChuong":"@c1896","cachCoDuoc":"Đã giữ trong tay trước khi bị ép giao ra","trangThai":"đã mất"},{"ten":"Vương Lâm","tuChuong":"@c1896","denChuong":"","cachCoDuoc":"Ép Đạo Nhất giao ra làm giá tha mạng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1896","loai":"đổi chủ","importance":"major","giaiDoan":"Đạo Nhất giao cho Vương Lâm","text":"Đạo Nhất bị dẫm ngực và bị Cửu Đế ép giao đầu lâu trẻ con tràn tử khí cho Vương Lâm rồi phá hư vô trốn mất.","anchor":"Đầu lâu này thoạt nhìn như của trẻ con. tràn ngập tử khí.","phamCap":"không rõ"}]},"capNhatToi":"@c1896","nguon":["@c1896"]},{"id":"dau-lau-tien-to","name":"Đầu lâu Tiên Tổ","cn":"","aliases":["Đầu lâu của Tiên Tổ","Đầu của tiên tổ"],"category":"phap-bao","categoryLabel":"Di vật","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã tổn hại @c1896","blurb":"Đầu lâu Tiên Tổ là di vật trọng yếu của tiên tộc, đang ở gần nơi Người điên hôn mê và được Cửu Đế cho phép Vương Lâm mang đi. Cửu Đế nói vật này đã tổn hại.","detail":"Đầu lâu Tiên Tổ vốn là trung tâm trong kế hoạch của Cửu Đế, dự định để các Đại Thiên Tôn tiên tộc cùng chia sẻ di vật Tiên Tổ nhằm tăng vọt tu vi và xóa bỏ Tiên Hoàng nhất mạch. Sau biến cố, Cửu Đế nhượng bộ cho Vương Lâm mang nó đi, nhưng dùng Liên Đạo Phi làm giới hạn không thể thương lượng.","phanLoaiPhu":"Di vật tiên tộc","nguonGoc":"Tiên Tổ","dacDiem":"Đã tổn hại theo lời Cửu Đế.","chuHienThoi":"Vương Lâm","congNang":["Là di vật mà Cửu Đế từng muốn các Đại Thiên Tôn tiên tộc chia sẻ để khiến tu vi tăng vọt @c1896"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1896","denChuong":"","cachCoDuoc":"Được Cửu Đế cho phép mang đi sau cục diện giao chiến","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1896","loai":"đổi chủ","importance":"normal","giaiDoan":"Được phép mang đi","text":"Cửu Đế nhượng bộ cho Vương Lâm mang đầu lâu Tiên Tổ đi, đồng thời nói rõ giới hạn là không được mang Liên Đạo Phi.","anchor":"Lão phu có thể cho ngươi mang đầu lâu của Tiên Tổ đi","phamCap":"không rõ"}]},"capNhatToi":"@c1896","nguon":["@c1896"]},{"id":"loan-dao-mau-den-cua-dao-nhat","name":"Loan đao màu đen của Đạo Nhất","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Loan đao","phamCap":"không rõ","soHuu":["Đạo Nhất"],"trangThai":"Đạo Nhất sử dụng @c1896","blurb":"Loan đao màu đen do Đạo Nhất lấy ra khi bị Trớ Thuật dồn vào đường cùng. Nó tỏa sát khí kinh nhân và được dùng trong đòn đồng quy vu tận nhằm chém Vương Lâm.","detail":"Đạo Nhất chụp hư không lấy ra loan đao màu đen, sát khí vờn quanh thân rồi chém xuống trong tiếng gào đồng quy vu tận. Đao quang chém sụp hơn chín mươi hư ảnh của Vương Lâm nhưng số hư ảnh còn lại vẫn xuyên qua và ngưng tụ trước mặt Đạo Nhất.","phanLoaiPhu":"Loan đao","hinhDang":"Loan đao màu đen","uyLuc":"Chém sụp hơn chín mươi hư ảnh của Vương Lâm trong một đòn.","dacDiem":"Vừa xuất hiện đã tỏa sát khí kinh nhân.","chuHienThoi":"Đạo Nhất","congNang":["Tỏa sát khí mạnh và chém sụp hàng loạt hư ảnh của Vương Lâm @c1896"],"chuSoHuu":[{"ten":"Đạo Nhất","tuChuong":"@c1896","denChuong":"","cachCoDuoc":"Chụp hư không biến ảo ra trong giao chiến","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1896","loai":"dùng","importance":"normal","giaiDoan":"Đòn đồng quy vu tận","text":"Đạo Nhất dùng loan đao màu đen trong đòn đồng quy vu tận, chém sụp phần lớn hư ảnh của Vương Lâm nhưng không ngăn được bản thể áp sát.","anchor":"Thanh loan đao này vừa xuất hiện liền tỏa ra sát khí kinh nhân","phamCap":"không rõ"}]},"capNhatToi":"@c1896","nguon":["@c1896"]},{"id":"hai-mat-cua-tien-to","name":"Hai mắt của tiên tổ","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"Không rõ","soHuu":["Song Tử"],"trangThai":"Song Tử đang giữ","blurb":"Di vật của tiên tổ do Song Tử thu được sau biến cố hoàng cung tiên tộc.","detail":"Song Tử nói nàng có được hai mắt của tiên tổ và sau khi trở về Tử Dương Tông sẽ bế quan, cho thấy vật này liên quan trực tiếp tới kế hoạch tu luyện kế tiếp của nàng.","phanLoaiPhu":"di vật truyền thừa","chuHienThoi":"Song Tử","congNang":["Khiến Song Tử quyết định trở về Tử Dương Tông bế quan @c1897"],"chuSoHuu":[{"ten":"Song Tử","tuChuong":"@c1897","denChuong":"","cachCoDuoc":"Có được sau biến cố hoàng cung tiên tộc","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1897","loai":"xuất hiện","importance":"normal","giaiDoan":"Song Tử có được","text":"Song Tử nói nàng đã có được hai mắt của tiên tổ và sẽ về Tử Dương Tông bế quan.","anchor":"Ta có được hai mắt của tiên tổ, sau khi trở về Tử Dương Tông sẽ bế quan"}]},"capNhatToi":"@c1897","nguon":["@c1897"]},{"id":"dau-an-tren-nguoi-lien-dao-phi","name":"Dấu ấn trên người Liên Đạo Phi","cn":"","category":"khac","categoryLabel":"Dấu ấn","phamCap":"Không rõ","soHuu":["Liên Đạo Phi","Hài Tử"],"trangThai":"Đã kích hoạt","blurb":"Dấu ấn do tộc của Hài Tử nhiều năm để lại trên người Liên Đạo Phi.","detail":"Dấu ấn này được mở ra khi Hài Tử thi triển bí thuật, giúp Liên Đạo Phi tiếp nhận truyền thừa tu vi tiên tổ và trở thành Đại Thiên Tôn ngủ say thay đầu tiên tổ trấn áp bảy mươi hai châu.","phanLoaiPhu":"dấu ấn truyền thừa","chuHienThoi":"Liên Đạo Phi","congNang":["Kích hoạt truyền thừa tu vi tiên tổ trong Liên Đạo Phi @c1897"],"chuSoHuu":[{"ten":"Liên Đạo Phi","tuChuong":"@c1897","denChuong":"","cachCoDuoc":"Bị tộc của Hài Tử nhiều năm để lại dấu ấn","trangThai":"da-kich-hoat"}],"tabs":{"tienTrinh":[{"chuong":"@c1897","loai":"khai phong","importance":"normal","giaiDoan":"Mở dấu ấn","text":"Hài Tử mở dấu ấn mà tộc nàng để lại trên Liên Đạo Phi để phối hợp bí thuật và truyền thừa tiên tổ.","anchor":"nhiều năm qua tộc ta cũng dần dần để lại dấu ấn trên người hắn"}]},"capNhatToi":"@c1897","nguon":["@c1897"]},{"id":"hai-tai-cua-tien-to","name":"Hai tai của Tiên Tổ","cn":"","aliases":[],"category":"khac","categoryLabel":"Bộ phận Tiên Tổ","phamCap":"không rõ","soHuu":["Võ Phong"],"trangThai":"Võ Phong đang có @c1898","blurb":"Hai tai của Tiên Tổ rơi vào tay Võ Phong sau biến cố hoàng cung.","detail":"Võ Phong đạt được hai tai của Tiên Tổ; sau khi xua tan hắc khí Trớ Thuật, vật này có thể khiến tu vi hắn tăng lên không ít.","congNang":["Giúp tu vi Võ Phong tăng lên sau khi Trớ Thuật được hóa giải @c1898"],"chuSoHuu":[{"ten":"Võ Phong","tuChuong":"@c1898","denChuong":"","cachCoDuoc":"đạt được sau biến cố liên quan Tiên Tổ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1898","loai":"nhắc tới","importance":"normal","giaiDoan":"Trong tay Võ Phong","text":"Hai tai Tiên Tổ được nhắc là chiến lợi phẩm của Võ Phong, có thể giúp hắn tăng tu vi sau khi hóa giải Trớ Thuật.","anchor":"Hơn nữa hắn đạt được hai tai của Tiên Tổ"}]},"capNhatToi":"@c1898","nguon":["@c1898"]},{"id":"ngoc-gian-than-thong-tang-chin-tang-hon-cac","name":"Ngọc giản thần thông tầng chín Tàng Hồn các","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Đại Hồn Môn"],"trangThai":"lưu tại tầng chín Tàng Hồn các @c1898","blurb":"Những ngọc giản trôi nổi tại tầng chín Tàng Hồn các, ghi chép thần thông cực mạnh của Đại Hồn Môn.","detail":"Tầng chín Tàng Hồn các có một vài ngọc giản trôi nổi, trong đó ghi chép các thần thông cực mạnh của Đại Hồn Môn, bao gồm Đa Trọng Huyễn Thuật đầy đủ mà Vương Lâm từng muốn có.","hinhDang":"ngọc giản trôi nổi","nguonGoc":"Đại Hồn Môn, Tàng Hồn các tầng chín","congNang":["Ghi chép thần thông cực mạnh của Đại Hồn Môn @c1898"],"tabs":{"tienTrinh":[{"chuong":"@c1898","loai":"xuất hiện","importance":"normal","giaiDoan":"Tầng chín Tàng Hồn các","text":"Ngọc giản thần thông xuất hiện ở tầng chín Tàng Hồn các khi Vương Lâm đi qua nơi này.","anchor":"Trên tầng chín này có một vài ngọc giản trôi nổi"}]},"capNhatToi":"@c1898","nguon":["@c1898"]},{"id":"bo-hai-cot-nhot-linh-hon-lao-to-dai-hon-mon","name":"Bộ hài cốt nhốt linh hồn lão tổ Đại Hồn Môn","cn":"","aliases":[],"category":"khac","categoryLabel":"Hài cốt phong khốn linh hồn","phamCap":"không rõ","soHuu":["Lão tổ Đại Hồn Môn"],"trangThai":"quỳ trong tầng mười Tàng Hồn các @c1898","blurb":"Bộ hài cốt nhốt linh hồn của lão tổ Đại Hồn Môn, được hé lộ trên tầng mười Tàng Hồn các, quỳ trước pho tượng Vương Lâm trong tư thế cầu xin tha thứ qua vô số năm.","detail":"Bộ hài cốt này không phải hài cốt bình thường mà có linh hồn bị nhốt bên trong. Nó tồn tại trên tầng mười Tàng Hồn các, quỳ gối trước pho tượng Vương Lâm, hai tay dâng não khô và trái tim đã ngừng đập — đầu nứt không não, ngực thủng không tim. Tư thế này gắn liền với lời khẩn cầu vạn cổ của lão tổ Đại Hồn Môn, lưu giữ trạng thái cầu xin tha thứ suốt vô số năm.","dacDiem":"Hài cốt nhốt linh hồn, đầu nứt không não, ngực thủng không tim, hai tay dâng não và tim.","congNang":["Lưu giữ trạng thái cầu xin tha thứ của lão tổ Đại Hồn Môn qua vô số năm @c1898"],"tabs":{"tienTrinh":[{"chuong":"@c1898","loai":"xuất hiện","importance":"major","giaiDoan":"Lời khẩn cầu vạn cổ","text":"Bộ hài cốt nhốt linh hồn lão tổ Đại Hồn Môn được hé lộ trên tầng mười Tàng Hồn các, quỳ trước tượng Vương Lâm để cầu xin tha thứ.","anchor":"Đây cũng không phải là một bộ hài cốt tầm thường mà là một bộ hài cốt nhốt linh hồn"}]},"capNhatToi":"@c1898","nguon":["@c1898"]},{"id":"ao-bong-thien-mien-cua-hua-lap-quoc","name":"Áo bông thiên miên của Hứa Lập Quốc","cn":"","category":"khac","categoryLabel":"Vật phẩm chống lạnh","phamCap":"chí bảo","soHuu":["Hứa Lập Quốc"],"trangThai":"đang được Hứa Lập Quốc sử dụng","blurb":"Áo bông chống lạnh được Hứa Lập Quốc khoe là chí bảo làm từ thiên miên. Vật này tự sinh khí tức ấm áp, giúp hắn ung dung trong hàn khí Hàn Châu.","detail":"Trong lúc đi qua Hàn Châu, Hứa Lập Quốc mặc nhiều lớp áo bông và giới thiệu một bộ làm từ thiên miên là chí bảo. Hắn nói vật này do mình đoạt được của Trần gia, có thể sinh ra khí tức ấm áp giữa vùng băng tuyết.","phanLoaiPhu":"vật phẩm chống lạnh","vatLieu":"thiên miên","congNang":["Sinh ra khí tức ấm áp để chống lại hàn khí."],"chuHienThoi":"Hứa Lập Quốc","chuSoHuu":[{"ten":"Hứa Lập Quốc","tuChuong":"@c1899","denChuong":"","cachCoDuoc":"Đoạt được của Trần gia theo lời Hứa Lập Quốc.","trangThai":"đang giữ"}],"capNhatToi":"@c1899","tabs":{"tienTrinh":[{"chuong":"@c1899","loai":"xuất hiện","importance":"normal","giaiDoan":"Khoe áo trong Hàn Châu","text":"Hứa Lập Quốc khoe áo bông thiên miên là chí bảo chống lạnh khi đi qua Hàn Châu.","anchor":"Bộ quần áo này chính là một vật chí bảo, dùng thiên miên để làm ra"}]},"nguon":["@c1899"]},{"id":"ao-bong-doat-tu-trieu-gia","name":"Áo bông đoạt từ Triệu gia","cn":"","category":"khac","categoryLabel":"Vật phẩm chống lạnh","phamCap":"không rõ","soHuu":["Hứa Lập Quốc"],"trangThai":"đang được Hứa Lập Quốc sử dụng","blurb":"Một áo bông chống lạnh khác được Hứa Lập Quốc khoe trong lúc trêu Lưu Kim Bưu. Theo lời hắn, mặc áo này vào giống như ôm một đống lửa.","detail":"Hứa Lập Quốc nói hắn từng giật dây Vương gia để đoạt áo bông này từ Triệu gia. Công năng nổi bật được chính hắn khoe là giữ ấm cực mạnh trong vùng băng tuyết.","phanLoaiPhu":"vật phẩm chống lạnh","congNang":["Giữ ấm mạnh, tạo cảm giác như đang ôm một đống lửa."],"chuHienThoi":"Hứa Lập Quốc","chuSoHuu":[{"ten":"Hứa Lập Quốc","tuChuong":"@c1899","denChuong":"","cachCoDuoc":"Giật dây Vương gia đoạt từ Triệu gia theo lời Hứa Lập Quốc.","trangThai":"đang giữ"}],"capNhatToi":"@c1899","tabs":{"tienTrinh":[{"chuong":"@c1899","loai":"xuất hiện","importance":"normal","giaiDoan":"Khoe áo đoạt được","text":"Hứa Lập Quốc khoe áo bông đoạt từ Triệu gia có khả năng giữ ấm rất mạnh.","anchor":"mặc trên người giống như là đang ôm một đống lửa"}]},"nguon":["@c1899"]},{"id":"khong-gian-tru-vat-cua-vuong-lam","name":"Không gian trữ vật của Vương Lâm","cn":"","category":"khac","categoryLabel":"Không gian trữ vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Không gian trữ vật được Vương Lâm dùng để bảo hộ Tống Trí trước khi tới núi hoang. (+) Không gian trữ vật mà Vương Lâm mở ra trong lúc vượt biển về cổ Tộc. [CAN-SOAT-GOP]","detail":"Vương Lâm hiện có thể mở không gian trữ vật dễ dàng mà không gây tổn hại, vì đã triệt tiêu được lực xé rách giữa động phủ giới và Tiên Cương đại lục.","chuHienThoi":"Vương Lâm","congNang":["Có thể được Vương Lâm mở ra mà không làm tổn hại nhờ triệt tiêu lực xé rách giữa động phủ giới và Tiên Cương đại lục @c1900"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1900","denChuong":"","cachCoDuoc":"đang sở hữu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1900","loai":"dùng","importance":"normal","giaiDoan":"mở không tổn hại","text":"Vương Lâm mở không gian trữ vật dễ dàng hơn trước vì đã triệt tiêu được lực xé rách giữa động phủ giới và Tiên Cương đại lục.","anchor":"Hắn đã có thể hoàn toàn triệt tiêu lực lượng xé rách giữa động phủ giới và Tiên Cương đại lục"}]},"capNhatToi":"@c1900","nguon":["@c1900","@c1923"]},{"id":"soi-toc-bac","name":"Sợi tóc bạc","cn":"","category":"khac","categoryLabel":"Vật phẩm lạ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"chưa rõ nguồn gốc","blurb":"Một sợi tóc bạc nằm trong không gian trữ vật của Vương Lâm.","detail":"Sợi tóc bạc khiến Vương Lâm có cảm giác rất quen thuộc, nhưng hắn chưa nghĩ ra nguồn gốc của nó.","hinhDang":"sợi tóc bạc","chuHienThoi":"Vương Lâm","dacDiem":"Gợi cảm giác quen thuộc nhưng lai lịch chưa rõ.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1900","denChuong":"","cachCoDuoc":"nằm trong không gian trữ vật","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1900","loai":"xuất hiện","importance":"normal","giaiDoan":"chưa rõ nguồn gốc","text":"Sợi tóc bạc xuất hiện trong không gian trữ vật và khiến Vương Lâm có cảm giác quen thuộc nhưng chưa nhận ra lai lịch.","anchor":"Thứ nhất là một sợi tóc bạc, thứ hai là một cái đầu lâu tràn ngập tử khí"}]},"capNhatToi":"@c1900","nguon":["@c1900"]},{"id":"ngoc-gian-ban-do-cua-binh-si-hac-thach-thanh","name":"Ngọc giản bản đồ của binh sĩ Hắc Thạch Thành","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản bản đồ","phamCap":"Không rõ","soHuu":["Đại hán Cổ Thần thứ nhất ở Hắc Thạch Thành","Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Bản đồ sơ lược do binh sĩ Hắc Thạch Thành dâng cho Vương Lâm. Nó ghi rõ vài quận phụ cận, giúp hắn xác định vị trí Hắc Thạch Thành và bố cục ba mươi sáu quận cổ tộc.","detail":"Ngọc giản này không đầy đủ, chỉ mô tả chi tiết vài quận gần Hắc Thạch Thành. Dù vậy, Vương Lâm nhờ nó biết Hắc Thạch Thành ở rìa Mộc Tang Quận thuộc Thủy cổ và nắm sơ bộ cách phân bố ba mươi sáu quận cổ tộc.","phanLoaiPhu":"Bản đồ cổ tộc sơ lược","hinhDang":"Ngọc giản","congNang":["Ghi chép sơ lược bản đồ vài quận phụ cận Hắc Thạch Thành @c1901","Giúp Vương Lâm xác định Hắc Thạch Thành nằm ở rìa Mộc Tang Quận thuộc Thủy cổ @c1901"],"chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Đại hán Cổ Thần thứ nhất ở Hắc Thạch Thành","tuChuong":"@c1901","denChuong":"@c1901","cachCoDuoc":"vốn mang theo bên người","trangThai":"đã dâng cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1901","denChuong":"","cachCoDuoc":"được đại hán Cổ Thần dâng sau khi hiển lộ cửu tinh","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1901","loai":"đổi chủ","importance":"normal","giaiDoan":"Dâng bản đồ","text":"Đại hán Cổ Thần dâng ngọc giản bản đồ sơ lược cho Vương Lâm sau khi nhận ra hắn là cửu tinh cổ Thần.","anchor":"chỉ có vài quận phụ cận là kể lại được chi tiết"}]},"capNhatToi":"@c1901","nguon":["@c1901"]},{"id":"ngoc-gian-ban-do-dao-co-hoang-thanh","name":"Ngọc giản bản đồ Đạo Cổ hoàng thành","aliases":["Ngọc giản bản đồ Đạo Cổ","Ngọc giản bản đồ tới Đạo Cổ hoàng thành"],"cn":"","category":"khac","categoryLabel":"Ngọc giản bản đồ","phamCap":"chưa rõ","soHuu":["Vương Lâm","Diệp Hải"],"trangThai":"Vương Lâm nhận từ Diệp Hải @c1903","blurb":"Ngọc giản chứa bản đồ dẫn tới Đạo Cổ hoàng thành, vốn do Diệp Hải giữ trong sứ đoàn Đạo Cổ. Tại @c1903, Diệp Hải cung kính giao ngọc giản cho Vương Lâm theo yêu cầu của hắn.","detail":"Ngọc giản bản đồ Đạo Cổ hoàng thành là vật phẩm do Diệp Hải mang theo trong sứ đoàn Đạo Cổ, bên trong ghi lại bản đồ chỉ đường tới Đạo Cổ hoàng thành. Khi Vương Lâm hỏi đường đến hoàng thành, Diệp Hải do dự rồi cung kính lấy ngọc giản ra đưa cho hắn, hoàn tất việc đổi chủ.","phanLoaiPhu":"bản đồ","hinhDang":"ngọc giản","chuHienThoi":"Vương Lâm","congNang":["Chứa bản đồ chỉ đường tới Đạo Cổ hoàng thành @c1903"],"chuSoHuu":[{"ten":"Diệp Hải","tuChuong":"@c1903","denChuong":"@c1903","cachCoDuoc":"mang theo trong sứ đoàn Đạo Cổ","trangThai":"đã giao ra"},{"ten":"Vương Lâm","tuChuong":"@c1903","denChuong":"","cachCoDuoc":"yêu cầu Diệp Hải đưa bản đồ Đạo Cổ hoàng thành","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1903","loai":"đổi chủ","importance":"major","giaiDoan":"Diệp Hải giao bản đồ","text":"Diệp Hải lấy ngọc giản bản đồ Đạo Cổ hoàng thành đưa cho Vương Lâm theo yêu cầu.","anchor":"lấy ra một ngọc giản cung kính đưa cho Vương Lâm","phamCap":"chưa rõ"}]},"capNhatToi":"@c1903","nguon":["@c1903"]},{"id":"ngoc-gian-danh-sach-cao-thu-tien-toc","name":"Ngọc giản danh sách cao thủ Tiên Tộc","cn":"","category":"khac","categoryLabel":"Ngọc giản tình báo","phamCap":"Hoàng thất tam tộc Cổ Tộc","soHuu":["Kế Đô hoàng tử","Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản ghi danh sách cao thủ Tiên Tộc do hoàng thất tam tộc Cổ Tộc nắm giữ. Hình vẽ của Vương Lâm cùng năm Đại Thiên Tôn phát kim quang, khác với các cao thủ còn lại.","detail":"Kế Đô đưa ngọc giản này cho Vương Lâm xem tại hành cung U Quận. Trong ngọc giản có hình năm Đại Thiên Tôn, các Dược Thiên Tôn và nhiều Thiên Tôn của Tiên Tộc, đồng thời cho thấy Cổ Tộc xếp Bạch Phát Dược Thiên Tôn vào diện đặc biệt trọng yếu.","phanLoaiPhu":"ngọc giản tình báo","hinhDang":"ngọc giản","nguonGoc":"Hoàng thất tam tộc Cổ Tộc","congNang":["Lưu hình và phân cấp cao thủ Tiên Tộc @c1904","Cho thấy hình Vương Lâm cùng năm Đại Thiên Tôn phát kim quang @c1904"],"dacDiem":"Danh sách này chỉ hoàng thất tam tộc mới được xem.","chuHienThoi":"Kế Đô hoàng tử","chuSoHuu":[{"ten":"Kế Đô hoàng tử","tuChuong":"@c1904","denChuong":"","cachCoDuoc":"Giữ ngọc giản của hoàng thất tam tộc","trangThai":"đang giữ"},{"ten":"Vương Lâm","tuChuong":"@c1904","denChuong":"","cachCoDuoc":"Được Kế Đô đưa cho xem","trangThai":"được xem"}],"tabs":{"tienTrinh":[{"chuong":"@c1904","loai":"xuất hiện","importance":"normal","giaiDoan":"Danh sách cao thủ Tiên Tộc","text":"Kế Đô đưa Vương Lâm xem ngọc giản danh sách cao thủ Tiên Tộc, trong đó hình Vương Lâm cùng năm Đại Thiên Tôn phát kim quang.","anchor":"danh sách này chỉ có hoàng thất của tam tộc mới được xem"}]},"capNhatToi":"@c1904","nguon":["@c1904"]},{"id":"to-gian-thuy-co-phong-an-mot-chi-co-to","name":"Tổ giản Thủy Cổ phong ấn một chỉ Cổ Tổ","cn":"","category":"phap-bao","categoryLabel":"Ngọc giản","phamCap":"Trọng bảo Thủy Cổ","soHuu":["Kế Đô hoàng tử","Vương Lâm"],"trangThai":"Vương Lâm đang giữ sau khi Kế Đô dâng tặng","blurb":"Tổ giản của nhất mạch Thủy Cổ, do phụ hoàng Kế Đô ban cho hắn từ lúc mới sinh. Bên trong phong ấn lực lượng một chỉ của Cổ Tổ, được Kế Đô dâng cho Vương Lâm như tín vật thể hiện thành ý cầu viện trong cuộc tranh ngôi Thủy Cổ Hoàng.","detail":"Tổ giản này thuộc Thủy Cổ nhất mạch, là vật do phụ hoàng Kế Đô ban cho hắn ngay sau khi sinh ra, mang ý nghĩa tín vật hoàng tử. Bên trong phong ấn lực lượng một chỉ của Cổ Tổ, đồng thời có thể dùng để cảm ngộ biến hóa của lực lượng ấy. Kế Đô dâng tổ giản cho Vương Lâm nhằm chứng minh hiếu tâm và thành ý cầu Vương Lâm trợ giúp trong cuộc tranh đoạt ngôi vị Thủy Cổ Hoàng.","phanLoaiPhu":"tín vật hoàng tử","nguonGoc":"Thủy Cổ nhất mạch, do phụ hoàng Kế Đô ban cho Kế Đô sau khi sinh ra","uyLuc":"Bên trong phong ấn lực lượng một chỉ của Cổ Tổ.","dacDiem":"Có thể dùng để cảm ngộ biến hóa lực lượng một chỉ Cổ Tổ.","chuHienThoi":"Vương Lâm","capNhatToi":"@c1905","congNang":["Phong ấn lực lượng một chỉ của Cổ Tổ @c1905","Dùng để cảm ngộ biến hóa lực lượng một chỉ Cổ Tổ @c1905"],"chuSoHuu":[{"ten":"Kế Đô hoàng tử","tuChuong":"@c1905","denChuong":"@c1905","cachCoDuoc":"Được phụ hoàng ban sau khi sinh ra","trangThai":"đã dâng cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1905","denChuong":"","cachCoDuoc":"Nhận từ Kế Đô làm hiếu tâm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1905","loai":"đổi chủ","importance":"major","giaiDoan":"Kế Đô dâng tổ giản","text":"Kế Đô dâng tổ giản cho Vương Lâm, nói bên trong phong ấn lực lượng một chỉ của Cổ Tổ và có thể dùng để cảm ngộ.","phamCap":"Trọng bảo Thủy Cổ","anchor":"Vật ấy là một tổ giản, bên trong phong ấn lực lượng một chỉ của Cổ Tổ."}]},"nguon":["@c1905"]},{"id":"ong-dich-moc-ban-nguyen-tinh-thuan","name":"Ống dịch mộc bản nguyên tinh thuần","cn":"","category":"nguyen-lieu","categoryLabel":"Dung dịch bản nguyên","phamCap":"Không rõ","soHuu":["Kế Đô hoàng tử","Vương Lâm"],"trangThai":"Vương Lâm đang giữ sau khi Kế Đô dâng tặng","blurb":"Ống dịch chứa mộc bản nguyên cực kỳ tinh thuần do Kế Đô chuẩn bị tặng Vương Lâm. Lai lịch vật này chưa rõ nhưng được Kế Đô xem là hợp với người tu đạo bản nguyên.","detail":"Kế Đô dựa vào thanh danh Bạch Phát Dược Thiên Tôn của Vương Lâm ở Tiên Tộc và đoán hắn tu đạo bản nguyên nên chuẩn bị ống dịch này làm lễ vật. Vương Lâm thu hộp ngọc chứa vật này sau khi để ngỏ đường lui Thủy Cổ.","phanLoaiPhu":"dung dịch bản nguyên","hinhDang":"ống dịch","nguonGoc":"Không rõ lai lịch","dacDiem":"Ẩn chứa mộc bản nguyên cực kỳ tinh thuần.","chuHienThoi":"Vương Lâm","capNhatToi":"@c1905","congNang":["Cung cấp mộc bản nguyên cực kỳ tinh thuần @c1905"],"chuSoHuu":[{"ten":"Kế Đô hoàng tử","tuChuong":"@c1905","denChuong":"@c1905","cachCoDuoc":"Chuẩn bị làm lễ vật cho Vương Lâm","trangThai":"đã dâng cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1905","denChuong":"","cachCoDuoc":"Nhận từ Kế Đô trong hộp ngọc","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1905","loai":"đổi chủ","importance":"normal","giaiDoan":"Dâng lễ vật bản nguyên","text":"Kế Đô dâng ống dịch cho Vương Lâm vì biết thanh danh của hắn ở Tiên Tộc và đoán hắn tu đạo bản nguyên.","anchor":"Thứ dịch này không thể biết lai lịch nhưng ẩn chứa mộc bản nguyên cực kỳ tinh thuần."}]},"nguon":["@c1905"]},{"id":"ngoc-gian-lien-lac-cua-ke-do","name":"Ngọc giản liên lạc của Kế Đô","cn":"","category":"phap-bao","categoryLabel":"Ngọc giản liên lạc","phamCap":"Không rõ","soHuu":["Kế Đô hoàng tử","Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Ngọc giản do Kế Đô giao cho Vương Lâm để duy trì liên lạc. Việc Vương Lâm yêu cầu vật này đánh dấu thỏa thuận chưa chính thức nhưng đã mở một đường dây giữa hai bên.","detail":"Sau khi Kế Đô quỳ xin làm nghĩa tử và dâng lễ vật, Vương Lâm chưa nhận lời ngay mà yêu cầu một ngọc giản liên lạc. Kế Đô mừng rỡ lấy ra giao cho hắn, xem đó là dấu hiệu Vương Lâm đã để ngỏ đường lui Thủy Cổ.","phanLoaiPhu":"ngọc giản liên lạc","chuHienThoi":"Vương Lâm","capNhatToi":"@c1905","congNang":["Dùng để liên lạc giữa Vương Lâm và Kế Đô @c1905"],"chuSoHuu":[{"ten":"Kế Đô hoàng tử","tuChuong":"@c1905","denChuong":"@c1905","cachCoDuoc":"Vật tùy thân dùng để liên lạc","trangThai":"đã giao cho Vương Lâm"},{"ten":"Vương Lâm","tuChuong":"@c1905","denChuong":"","cachCoDuoc":"Yêu cầu Kế Đô giao để liên lạc","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1905","loai":"đổi chủ","importance":"normal","giaiDoan":"Thiết lập liên lạc","text":"Vương Lâm yêu cầu ngọc giản liên lạc và Kế Đô lập tức lấy ra giao cho hắn trong vui mừng.","anchor":"Thân thể Kế Đô chấn động, khuôn mặt lộ vẻ mừng như điên. Hắn lập tức lấy ra một ngọc giản, kích động đưa cho Vương Lâm."}]},"nguon":["@c1905"]},{"id":"ngoc-gian-than-phan-thien-khong-thanh","name":"Ngọc giản thân phận Thiên Không Thành","cn":"","category":"khac","categoryLabel":"vật chứng thân phận","phamCap":"không rõ","soHuu":["tộc nhân được phép vào Đạo Cổ hoàng thành"],"trangThai":"được dùng theo quy tắc vào thành","blurb":"Vật chứng thân phận cần có khi tiến vào Thiên Không Thành. Người không có ngọc giản này theo quy tắc sẽ không thể bước vào thành.","detail":"Cấm chế phòng hộ Đạo Cổ hoàng thành yêu cầu người tiến vào xuất trình ngọc giản thân phận. Quy tắc này làm nổi bật việc Vương Lâm xuyên qua cấm chế mà không cần vật chứng như một ngoại lệ vượt thường thức.","phanLoaiPhu":"ngọc giản thân phận","congNang":["Xác nhận thân phận người muốn vào Đạo Cổ hoàng thành qua cấm chế phòng hộ @c1906"],"tabs":{"tienTrinh":[{"chuong":"@c1906","loai":"xuất hiện","importance":"normal","giaiDoan":"quy tắc vào thành","text":"Ngọc giản thân phận Thiên Không Thành được nêu là điều kiện để người thường bước vào Đạo Cổ hoàng thành.","anchor":"Những người tiến vào nơi này cần có ngọc giản thân phận, nếu không không thể bước vào thành nửa bước."}]},"capNhatToi":"@c1906","nguon":["@c1906"]},{"id":"lu-huong-truoc-dao-co-dien","name":"Lư hương trước Đạo Cổ Điện","cn":"","category":"khac","categoryLabel":"lư hương nghi lễ","phamCap":"không rõ","soHuu":["Đạo Cổ Điện"],"trangThai":"đang đặt trước Đạo Cổ Điện","blurb":"Lư hương đặt trước Đạo Cổ Điện, nhận lễ bái của tộc nhân Đạo Cổ và khiến khói xanh tăng theo người bái. Khi Vương Lâm vái sư tôn Huyền La, lư hương bạo phát dị tượng, khói xanh tràn khắp Thiên Không Thành.","detail":"Lư hương nằm ngay trước Đạo Cổ Điện, bên trong có chín cây hương gần như vạn cổ không tắt. Bình thường, mỗi khi tộc nhân Đạo Cổ bái lạy, khói xanh từ lư hương tăng lên tương ứng. Tuy nhiên, khi Vương Lâm chỉ vái một vái trước cửa điện để lạy sư tôn, lư hương phát tiếng nổ lớn, chín cây hương cháy dữ dội, khói xanh dày lên gấp vô số lần rồi phủ khắp Thiên Không Thành, thậm chí khom mình như sắp sụp đổ trước sức nặng của một vái đó.","phanLoaiPhu":"lư hương nghi lễ","hinhDang":"lư hương đặt trước Đạo Cổ Điện, có chín cây hương bên trong","congNang":["Nhận lễ bái của tộc nhân Đạo Cổ và khiến khói xanh tăng lên tương ứng @c1906","Bộc phát khói xanh phủ khắp Thiên Không Thành khi Vương Lâm vái sư tôn @c1906"],"uyLuc":"Một vái của Vương Lâm khiến khói xanh dày gấp vô số lần, tràn khắp Thiên Không Thành và khom mình như sắp sụp đổ.","chuSoHuu":[{"ten":"Đạo Cổ Điện","tuChuong":"@c1906","denChuong":"","cachCoDuoc":"đặt trước điện như vật nghi lễ","trangThai":"đang quản giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1906","loai":"xuất hiện","importance":"major","giaiDoan":"dị tượng một vái","text":"Lư hương trước Đạo Cổ Điện phát tiếng nổ khi Vương Lâm vái sư tôn, khiến chín cây hương cháy dữ dội và khói xanh phủ Thiên Không Thành rồi khom mình.","anchor":"trong lư hương phát ra tiếng nổ ầm vang. Chỉ thấy chín cây hương bốc cháy"}]},"capNhatToi":"@c1906","nguon":["@c1906"]},{"id":"chin-cay-huong-trong-lu-dao-co-dien","name":"Chín cây hương trong lư Đạo Cổ Điện","cn":"","category":"khac","categoryLabel":"hương nghi lễ","phamCap":"không rõ","soHuu":["Đạo Cổ Điện"],"trangThai":"đang cháy trong lư hương","blurb":"Chín cây hương trong lư trước Đạo Cổ Điện, được mô tả gần như vĩnh viễn không cháy hết qua năm tháng vạn cổ. Khi Vương Lâm vái, chúng bốc cháy nhanh bằng mắt thường thấy được.","detail":"Chín cây hương tạo ra khói xanh trong nghi lễ Đạo Cổ Điện, khói xanh thường tăng theo số người quỳ lạy. Dị tượng ở chương này cho thấy chúng phản ứng dữ dội với một vái của Vương Lâm, khiến khói xanh bùng lên vượt xa bình thường.","phanLoaiPhu":"hương nghi lễ","dacDiem":"Gần như vĩnh viễn không đốt hết qua vạn cổ, nhưng cháy dữ dội dưới một vái của Vương Lâm.","congNang":["Sinh khói xanh trong lư hương nghi lễ trước Đạo Cổ Điện @c1906"],"tabs":{"tienTrinh":[{"chuong":"@c1906","loai":"dùng","importance":"normal","giaiDoan":"khói xanh bạo phát","text":"Chín cây hương trong lư Đạo Cổ Điện vốn vạn cổ không tắt nhưng bốc cháy nhanh khi Vương Lâm vái.","anchor":"Ở chín cây hương trong lô giống như vĩnh viễn không đốt hết, trải qua năm tháng vạn cổ vẫn như thế."}]},"capNhatToi":"@c1906","nguon":["@c1906"]},{"id":"ngoc-boi-mau-tim-cua-dao-co-hoang-ton","name":"Ngọc bội màu tím của Đạo Cổ hoàng tôn","cn":"","aliases":[],"category":"khac","categoryLabel":"Tín vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Tín vật màu tím do Đạo Cổ hoàng tôn đích thân ban cho Vương Lâm, cho phép người mang nó tùy ý ra vào hoàng cung Đạo Cổ và cầu kiến hoàng tôn bất cứ lúc nào.","detail":"Ngọc bội được Đạo Cổ hoàng tôn trao cho Vương Lâm trước Đạo Cổ Điện, đóng vai trò tín vật xác nhận đặc quyền của người sở hữu trong phạm vi hoàng cung Đạo Cổ. Với vật này, Vương Lâm không bị ngăn trở khi muốn vào hoàng cung hay yết kiến hoàng tôn.","phanLoaiPhu":"Tín vật hoàng quyền","hinhDang":"Ngọc bội màu tím","chuHienThoi":"Vương Lâm","congNang":["Cho phép người mang tùy ý ra vào hoàng cung Đạo Cổ và cầu kiến Đạo Cổ hoàng tôn bất cứ lúc nào (@c1908)"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1908","denChuong":"","cachCoDuoc":"Được Đạo Cổ hoàng tôn ban trước Đạo Cổ Điện","trangThai":"dang-co"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1908","loai":"đổi chủ","importance":"major","giaiDoan":"Ban trước Đạo Cổ Điện","text":"Đạo Cổ hoàng tôn ban ngọc bội màu tím cho Vương Lâm làm tín vật ra vào hoàng cung và cầu kiến hoàng tôn.","anchor":"với vật này ngươi có thể tùy ý ra vào hoàng cung"}]},"capNhatToi":"@c1908","nguon":["@c1908"]}]};